// TreeSwasthya Tab Switching Logic
function switchTreeTab(tabId, btn) {
    if (!btn) return;
    const nav = btn.parentElement;
    nav.querySelectorAll('.dairy-tab-btn').forEach(b => b.classList.remove('active'));
    btn.classList.add('active');

    // Find the parent container that holds these panes
    let container = document.getElementById('tree-dash');
    if (container) {
        let parent = container.parentElement;
        parent.querySelectorAll('.dairy-pane').forEach(pane => {
            if (pane.id && pane.id.startsWith('tree-')) {
                pane.classList.remove('active');
                pane.style.display = 'none';
            }
        });
    }

    // Show selected pane
    const selected = document.getElementById(tabId);
    if (selected) {
        selected.classList.add('active');
        selected.style.display = 'block';
    }
}



