window.showPage = function (pageKey) {

    const container = document.getElementById('page-container');
    if (!container) return;

    // Use modern overview if available
    if (pageKey === 'overview' && window.newOverviewTemplate) {
        container.innerHTML = window.newOverviewTemplate;
        currentPage = pageKey;
    } else if (pages[pageKey]) {
        container.innerHTML = pages[pageKey];
        currentPage = pageKey;
    } else {
        // Page not found, show message
        container.innerHTML = '<div style="padding: 40px; text-align: center; color: var(--text-secondary);">Page not found: ' + escapeHtml(pageKey) + '</div>';
        return;
    }

    // Update sidebar active state
    document.querySelectorAll('.menu-item').forEach(item => {
        item.classList.remove('active');
        if (item.dataset.page === pageKey) {
            item.classList.add('active');
        }
    });

    // Update header title
    const titleEl = document.getElementById('current-page-title');
    if (titleEl) {
        const activeNav = document.querySelector(`.menu-item[data-page="${pageKey}"] .nav-label`);
        titleEl.textContent = activeNav ? activeNav.textContent : pageKey;
    }

    // Initialize module-specific scripts
    if (pageKey === 'overview') {
        if (typeof initOverview === 'function') initOverview();
    }
    if (pageKey === 'grid' && typeof initGridHub === 'function') initGridHub();
    if (pageKey === 'solar') {
        if (typeof initSolarHub === 'function') initSolarHub();
        if (typeof generateInverterGrid === 'function') generateInverterGrid();
    }
    if (pageKey === 'wind' && typeof initWindHub === 'function') initWindHub();
    if (pageKey === 'biogas' && typeof initBiogasHub === 'function') initBiogasHub();
    if (pageKey === 'logistics' && typeof initLogisticsHub === 'function') initLogisticsHub();
    if (pageKey === 'water' && typeof initWaterHub === 'function') initWaterHub();
    if (pageKey === 'vedic' && typeof initVedicHub === 'function') initVedicHub();
    if (pageKey === 'trust' && typeof initTrustHub === 'function') initTrustHub();
    if (pageKey === 'tourism' && typeof initTourismHub === 'function') initTourismHub();
    if (pageKey === 'command' && typeof initCommandHub === 'function') initCommandHub();
    if (pageKey === 'aqua') { setTimeout(initAquaHubEnterprise, 100); }
    if (pageKey === 'poultry') { setTimeout(initPoultryHubEnterprise, 100); }

    if (pageKey === 'hydrogen' && typeof initGreenH2Hub === 'function') initGreenH2Hub();
    if (pageKey === 'hydro' && typeof initHydroHub === 'function') initHydroHub();
    if (pageKey === 'kinetic' && typeof initKinetic === 'function') initKinetic();
    if (pageKey === 'cattle') {
        if (typeof initCtDashboard === 'function') initCtDashboard();
        if (typeof generateCowDB === 'function') generateCowDB();
    }
    if (pageKey === 'vermi' && typeof initVermiHub === 'function') initVermiHub();
    if (pageKey === 'tree' && typeof initTreeHub === 'function') initTreeHub();
    if (pageKey === 'paint' && typeof initPaintHub === 'function') initPaintHub();
    if (pageKey === 'carbon' && typeof initCarbonHub === 'function') initCarbonHub();
    if (pageKey === 'crm' && typeof initCtDashboard === 'function') initCtDashboard();
    if (pageKey === 'vet') {
        if (typeof initVetHub === 'function') initVetHub();
        if (typeof generateERBoard2 === 'function') generateERBoard2();
    }
    if (pageKey === 'finance' && typeof initCtFinance === 'function') initCtFinance();

    // Legacy/Simulator initializers (only if specific container exists)
    if (pageKey === 'ai' && typeof initSmartGridAI === 'function') initSmartGridAI();

}

