// --- HYDROPOWER SIMULATION LOGIC ---
let turbineRot = 0;
let hydroInterval;

function initHydroSim() {
    if (hydroInterval) clearInterval(hydroInterval);
    updateHydroSimulation(document.getElementById('demandSlider')?.value || 0);

    // Animation Loop
    hydroInterval = setInterval(() => {
        const slider = document.getElementById('demandSlider');
        if (!slider) { clearInterval(hydroInterval); return; }

        const demand = parseInt(slider.value);
        const turbine = document.getElementById('turbine');

        if (demand > 0) {
            // Spin turbine based on demand speed
            turbineRot += (demand / 5);
            turbine.style.transform = `rotate(${turbineRot}deg)`;
        }
    }, 50);
}

function updateHydroSimulation(val) {
    const demand = parseInt(val);

    // UI Elements
    const readout = document.getElementById('demand-readout');
    const gen = document.getElementById('h-gen');
    const waterFlow = document.getElementById('water-flow');
    const upperCap = document.getElementById('h-reserve');
    const waterUpper = document.getElementById('water-upper');
    const waterLower = document.getElementById('water-lower');

    const pumpCard = document.getElementById('h-pump-card');
    const returnPath = document.getElementById('return-path');

    if (demand === 0) {
        // PUMPING MODE (Solar active, generating 0)
        readout.innerText = "Low (Pumping)";
        readout.style.color = "#00b0ff";
        gen.innerText = "0.0";
        waterFlow.style.height = "0%";

        // Return active
        pumpCard.style.opacity = "1";
        returnPath.classList.add('active');

        // Refill upper tank slowly visually
        waterUpper.style.height = "85%";
        waterLower.style.height = "15%";
        upperCap.innerText = "85%";

    } else {
        // GENERATING MODE
        if (demand < 50) {
            readout.innerText = "Medium Surge";
            readout.style.color = "#fbbf24";
        } else {
            readout.innerText = "CRITICAL SURGE";
            readout.style.color = "#ff1744";
        }

        // Stop pumps
        pumpCard.style.opacity = "0.5";
        returnPath.classList.remove('active');

        // Calculate Generation (up to ~18 MW)
        const genMW = (demand / 100) * 18.4;
        gen.innerText = genMW.toFixed(1);

        // Show water flowing down pipe
        waterFlow.style.height = "100%";

        // Drain upper tank, fill lower tank proportionally
        const drainAmount = 85 - (demand * 0.4); // Drain down to max 45% remaining
        const fillAmount = 15 + (demand * 0.4);

        waterUpper.style.height = `${drainAmount}% `;
        waterLower.style.height = `${fillAmount}% `;
        upperCap.innerText = `${Math.round(drainAmount)}% `;
    }
}



// --- VERMICOMPOST IOT LOGIC ---
let vermiInterval;
function initVermiGrid() {
    const grid = document.getElementById('vermi-bed-grid');
    if (!grid) return;

    // Clear old if exists
    grid.innerHTML = '';

    let criticalCount = 0;
    let totalMoisture = 0;
    const NUM_BEDS = 150; // Visual representation

    // Generate Cells
    for (let i = 1; i <= NUM_BEDS; i++) {
        const cell = document.createElement('div');
        cell.className = 'bed-cell';

        // Randomize initial state
        const rand = Math.random();
        let stateClass = 'bed-optimal';
        let moisture = 75; // Baseline

        if (rand > 0.92) {
            stateClass = 'bed-dry';
            moisture = Math.floor(Math.random() * 10) + 50; // 50-59
            criticalCount++;
        } else if (rand > 0.8) {
            stateClass = 'bed-warn';
            moisture = Math.floor(Math.random() * 10) + 60; // 60-69
        } else {
            moisture = Math.floor(Math.random() * 10) + 70; // 70-79
        }

        totalMoisture += moisture;

        cell.classList.add(stateClass);
        cell.innerText = moisture + '%';
        cell.dataset.moisture = moisture;

        // Click action: Sprinkler
        cell.onclick = function () {
            if (!this.classList.contains('bed-optimal')) {
                this.classList.remove('bed-dry', 'bed-warn');
                this.classList.add('sprinkling');
                setTimeout(() => {
                    this.classList.remove('sprinkling');
                    this.classList.add('bed-optimal');
                    this.innerText = '78%';
                    updateVermiStats();
                }, 1000);
            }
        };

        grid.appendChild(cell);
    }

    var _el_v_critical_count = document.getElementById('v-critical-count'); if (_el_v_critical_count) _el_v_critical_count.innerText = criticalCount;
    var _el_v_avg_moist = document.getElementById('v-avg-moist'); if (_el_v_avg_moist) _el_v_avg_moist.innerText = Math.round(totalMoisture / NUM_BEDS) + '%';

    // Setup random drying interval
    if (vermiInterval) clearInterval(vermiInterval);
    vermiInterval = setInterval(() => {
        const cells = document.querySelectorAll('.bed-cell.bed-optimal');
        if (cells.length > 0) {
            const randomCell = cells[Math.floor(Math.random() * cells.length)];
            randomCell.classList.remove('bed-optimal');
            // 50/50 chance of warn or dry
            if (Math.random() > 0.5) {
                randomCell.classList.add('bed-warn');
                randomCell.innerText = '65%';
            } else {
                randomCell.classList.add('bed-dry');
                randomCell.innerText = '55%';
            }
            updateVermiStats();
        }
    }, 4000); // Heat dries a bed every 4 seconds
}

function updateVermiStats() {
    const grid = document.getElementById('vermi-bed-grid');
    if (!grid) return;

    const criticals = grid.querySelectorAll('.bed-dry').length;
    var _el_v_critical_count = document.getElementById('v-critical-count'); if (_el_v_critical_count) _el_v_critical_count.innerText = criticals;

    const warns = grid.querySelectorAll('.bed-warn').length;
    const optimals = grid.querySelectorAll('.bed-optimal').length;

    // Rough average reconstruction to save looping map
    const totalCount = criticals + warns + optimals;
    const avg = ((criticals * 55) + (warns * 65) + (optimals * 75)) / totalCount;

    var _el_v_avg_moist = document.getElementById('v-avg-moist'); if (_el_v_avg_moist) _el_v_avg_moist.innerText = Math.round(avg) + '%';
}


// --- BIO-PAINTS FACTORY LOGIC ---
let paintInterval;
function initPaintFactory() {
    if (paintInterval) clearInterval(paintInterval);

    let totalLiters = 1245600;

    paintInterval = setInterval(() => {
        const literEl = document.getElementById('p-liters');
        if (!literEl) { clearInterval(paintInterval); return; }

        // Factory runs at ~60 Liters per second (3 buckets of 20L)
        totalLiters += 60;

        // Format with commas
        literEl.innerText = totalLiters.toString().replace(/\B(?=(\d{3})+(?!\d))/g, ",");

        // Update revenue estimating $3.40 profit per liter
        const rev = (totalLiters * 3.4).toFixed(0);

        let revFormatted;
        if (rev >= 1000000) {
            revFormatted = "$" + (rev / 1000000).toFixed(2) + "M";
        } else {
            revFormatted = "$" + rev.toString().replace(/\B(?=(\d{3})+(?!\d))/g, ",");
        }

        var _el_p_rev = document.getElementById('p-rev'); if (_el_p_rev) _el_p_rev.innerText = revFormatted;

    }, 1000);
}


// --- KINETIC TRACKER LOGIC ---
let kineticInterval;
function initKinetic() {
    if (kineticInterval) clearInterval(kineticInterval);

    kineticInterval = setInterval(() => {
        const tKur = document.getElementById('kems-output');
        if (!tKur) { clearInterval(kineticInterval); return; }

        const kur = 6.10 + (Math.random() * 0.1 - 0.05);
        const bel = 5.20 + (Math.random() * 0.08 - 0.04);
        const gad = 4.00 + (Math.random() * 0.02 - 0.01);
        const hyd = 0.08 + (Math.random() * 0.01 - 0.005);

        const total = (kur + bel + gad + hyd).toFixed(2);
        tKur.innerText = total + " MW";

        const stepsEl = document.getElementById('kems-steps');
        if (stepsEl) {
            const baseSteps = 42000;
            const variation = Math.floor(Math.random() * 1000 - 500);
            stepsEl.innerText = (baseSteps + variation).toLocaleString();
        }

    }, 2000);
}


