// ========== PHASE 20: COW INTELLIGENCE DATABASE ==========
async function generateCowDB(filterBreed = "all", searchId = "") {
    const grid = document.getElementById('cow-db-results');
    if (!grid) return;
    grid.innerHTML = '<div style="grid-column: 1/-1; text-align:center; padding: 2rem; color: var(--text-2);">Loading real-time cattle data...</div>';

    let query = '?order=id.asc';
    if (filterBreed !== 'all' && typeof filterBreed !== 'undefined') {
        query += `& breed=eq.${encodeURIComponent(filterBreed)} `;
    }
    const cows = await window.insforge.fetch('cattle', query);

    if (!cows || cows.length === 0) {
        grid.innerHTML = '<div style="grid-column: 1/-1; text-align:center; padding: 2rem;">No cattle found.</div>';
        return;
    }

    const tagClass = { 'Lactating': 'tag-lactating', 'Dry': 'tag-dry', 'Gestation': 'tag-gestation', 'Calf': 'tag-calf' };
    let html = '';

    cows.forEach(cow => {
        if (searchId && !cow.rfid.toLowerCase().includes(searchId.toLowerCase())) return;

        let statusBadge = `< span class="cow-tag ${tagClass[cow.status] || 'tag-dry'}" > ${cow.status}</span > `;
        let tempAlert = cow.temperature > 39.0 ? 'warning' : 'normal';
        let avatar = `https://xsgames.co/randomusers/assets/avatars/female/${(cow.id % 24) + 1}.jpg`;

        html += `
       <div class="cow-profile"onclick="event.stopPropagation()">
           <div class="c-head">
               <img src="${avatar}"alt="Cow">
               <div class="c-info">
                   <div style="font-weight: 600; font-size: 1.1rem">${cow.rfid}</div>
                   <div style="color: var(--text-2); font-size: 0.85rem">${cow.breed} · ${cow.age} yrs</div>
                   <div style="margin-top: 5px">${statusBadge}</div>
               </div>
               <div class="${tempAlert === 'warning' ? 'live-dot' : 'live-dot'}"style="${tempAlert === 'warning' ? 'background: #dc3545;' : ''}"title="Live Vitals"></div>
           </div>
           <div class="vitals-row">
               <div class="vital-card ${tempAlert}">
                   <div class="v-label">Body Temp</div><div class="v-val">${cow.temperature}°C</div>
               </div>
               <div class="vital-card">
                   <div class="v-label">Milk/Day</div><div class="v-val">${cow.milk_yield} L</div>
               </div>
           </div>
           <div class="vitals-row">
               <div class="vital-card">
                   <div class="v-label">Steps (24h)</div><div class="v-val">${cow.steps}</div>
               </div>
               <div class="vital-card">
                   <div class="v-label">Heart Rate</div><div class="v-val">${cow.heart_rate} bpm</div>
               </div>
           </div>
       </div>`;
    });
    grid.innerHTML = html || '<div style="grid-column: 1/-1; text-align:center; padding: 2rem;">No cattle match.</div>';
}
function searchCowDB() {
    const breed = document.getElementById('cow-breed-filter')?.value || 'all';
    const search = document.getElementById('cow-id-search')?.value || '';
    generateCowDB(breed, search);
}

// ========== PHASE 21: VET ER ADMISSIONS BOARD ==========
async function generateERBoard2() {
    const grid = document.getElementById('er-board-grid');
    if (!grid) return;
    grid.innerHTML = '<div style="grid-column: 1/-1; text-align:center; padding: 2rem;">Loading live admissions...</div>';

    const cases = await window.insforge.fetch('vet_cases', '?order=bed_id.asc');
    if (!cases) return;

    let stats = { critical: 0, stable: 0, recovery: 0, empty: 0 };
    let html = '';

    cases.forEach(c => {
        stats[c.status]++;
        let statusColor = { 'critical': '#dc3545', 'stable': '#ffc107', 'recovery': '#198754', 'empty': 'rgba(255,255,255,0.05)' }[c.status];

        if (c.status === 'empty') {
            html += `<div class="er-bed"><div class="er-bed-header"><span class="bed-id">${c.bed_id}</span><span class="bed-status"style="background: rgba(255,255,255,0.1)">EMPTY</span></div><div class="er-patient-info"style="opacity: 0.3; justify-content: center; align-items: center; min-height: 80px;"><div style="font-size: 0.8rem;">Awaiting Patient</div></div></div>`;
            return;
        }

        let pColor = c.status === 'critical' ? 'var(--danger)' : (c.status === 'stable' ? 'var(--warning)' : 'var(--success)');

        html += `
       <div class="er-bed">
           <div class="er-bed-header">
               <span class="bed-id">${c.bed_id}</span>
               <span class="bed-status"style="background: ${statusColor}20; color: ${statusColor}; border: 1px solid ${statusColor}40;">${c.status.toUpperCase()}</span>
           </div>
           <div class="er-patient-info">
               <div class="p-row"><span class="p-lbl">Patient:</span><span class="p-val"style="font-weight:600">${c.rfid}</span></div>
               <div class="p-row"><span class="p-lbl">Breed:</span><span class="p-val">${c.breed}</span></div>
               <div class="p-row"><span class="p-lbl">Diagnosis:</span><span class="p-val"style="color: var(--text-1)">${c.diagnosis}</span></div>
               <div class="p-row"><span class="p-lbl">Treating:</span><span class="p-val">${c.vet_name}</span></div>
           </div>
           <div class="er-progress-section">
               <div style="display: flex; justify-content: space-between; font-size: 0.7rem; color: var(--text-2); margin-bottom: 5px;">
                   <span>Recovery Timeline</span><span>${c.recovery_pct}%</span>
               </div>
               <div class="er-progress-bar"><div class="er-progress-fill"style="width: ${c.recovery_pct}%; background: ${pColor};"></div></div>
               <div style="margin-top: 5px; font-size:0.75rem; color: var(--text-2)">Admitted: ${c.hours_admitted} hrs ago</div>
           </div>
       </div>`;
    });

    grid.innerHTML = html;

    let legHtml = Object.keys(stats).map(k => {
        let sc = { 'critical': '#dc3545', 'stable': '#ffc107', 'recovery': '#198754', 'empty': 'rgba(255,255,255,0.1)' }[k];
        return `<div class="legend-item"><span class="l-dot"style="background: ${sc}"></span>${k.charAt(0).toUpperCase() + k.slice(1)}<span style="font-weight:bold; margin-left:5px">${stats[k]}</span></div>`;
    }).join('');

    const counts = document.getElementById('er-legend-counts');
    if (counts) counts.innerHTML = legHtml;
}
function generateInverterGrid() {
    const grid = document.getElementById('inv-array-grid');
    if (!grid) return;

    let html = '';
    let okCount = 0, warnCount = 0, critCount = 0, offCount = 0;

    for (let i = 0; i < 1000; i++) {
        const rand = Math.random();
        let cls, title;
        if (rand < 0.82) { cls = 'inv-ok'; okCount++; title = 'Optimal'; }
        else if (rand < 0.92) { cls = 'inv-warn'; warnCount++; title = 'Dust/Degraded'; }
        else if (rand < 0.96) { cls = 'inv-crit'; critCount++; title = 'Critical'; }
        else { cls = 'inv-offline'; offCount++; title = 'Offline'; }

        html += `<div class="inv-cell ${cls}"title="INV-${String(i + 1).padStart(4, '0')}: ${title}"data-inv="${i}"></div>`;
    }

    grid.innerHTML = html;

    // Update stats
    const el = (id) => document.getElementById(id);
    if (el('inv-ok-count')) el('inv-ok-count').textContent = okCount;
    if (el('inv-warn-count')) el('inv-warn-count').textContent = warnCount;
    if (el('inv-crit-count')) el('inv-crit-count').textContent = critCount;
    if (el('inv-off-count')) el('inv-off-count').textContent = offCount;

    // Enable dispatch button
    const btn = document.getElementById('inv-dispatch-btn');
    if (btn) btn.disabled = (warnCount + critCount) === 0;
}

function dispatchCleaningRobots() {
    const grid = document.getElementById('inv-array-grid');
    if (!grid) return;

    const btn = document.getElementById('inv-dispatch-btn');
    if (btn) { btn.disabled = true; btn.textContent = '🤖 Dispatching...'; }

    const bad = grid.querySelectorAll('.inv-warn, .inv-crit');
    let cleaned = 0;

    bad.forEach((cell, idx) => {
        setTimeout(() => {
            cell.classList.remove('inv-warn', 'inv-crit');
            cell.classList.add('inv-cleaning');
            cleaned++;

            setTimeout(() => {
                cell.classList.remove('inv-cleaning');
                cell.classList.add('inv-ok');

                if (cleaned === bad.length) {
                    if (btn) { btn.textContent = '✅ All Clean!'; }
                    const el = (id) => document.getElementById(id);
                    if (el('inv-warn-count')) el('inv-warn-count').textContent = '0';
                    if (el('inv-crit-count')) el('inv-crit-count').textContent = '0';
                    if (el('inv-ok-count')) el('inv-ok-count').textContent = 1000 - parseInt(el('inv-off-count')?.textContent || 0);
                    setTimeout(() => { if (btn) { btn.textContent = '🤖 Dispatch Cleaning Robots'; btn.disabled = false; } }, 3000);
                }
            }, 500);
        }, idx * 15);
    });
}


// Phase 25: Notifications Dropdown
let notifsLoaded = false;
async function toggleNotifs(e) {
    if (e) e.stopPropagation();
    const drop = document.getElementById('notif-dropdown');
    if (!drop) return;

    drop.classList.toggle('hidden');

    if (!drop.classList.contains('hidden') && !notifsLoaded) {
        await loadNotifs();
    }
}

async function loadNotifs() {
    const list = document.getElementById('notif-list');
    if (!list) return;
    try {
        const alerts = await window.insforge.fetch('alerts', '?order=created_at.desc&limit=5');
        if (!alerts || alerts.length === 0) {
            list.innerHTML = '<div style="padding: 15px; text-align: center; color: var(--text-2);">No alerts.</div>';
            return;
        }

        let html = '';
        alerts.forEach(a => {
            const time = new Date(a.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
            const sevClass = a.severity === 'high' ? 'n-high' : (a.severity === 'medium' ? 'n-medium' : 'n-low');
            html += `
           <div class="notif-item">
               <div class="n-header">
                   <span class="n-module ${sevClass}">[${a.severity.toUpperCase()}] ${a.module}</span>
                   <span class="n-time">${time}</span>
               </div>
               <div>${a.message}</div>
           </div>`;
        });
        list.innerHTML = html;
        notifsLoaded = true;
    } catch (err) {
        list.innerHTML = '<div style="padding: 15px; text-align: center; color: var(--danger);">Error loading alerts.</div>';
    }
}

