// --- PHASE 27: SMART GRID AI LOGIC ---
let aiLogInterval = null;

function initSmartGridAI() {
    const logBox = document.getElementById('ai-decision-log');
    if (!logBox) return;

    // Clear old interval if exists
    if (aiLogInterval) clearInterval(aiLogInterval);

    const actions = [
        "Rerouted 50kW from Solar A to Biogas buffer.",
        "Detected 2% efficiency drop in Inverter 4 (Kurnool). Auto-compensated.",
        "Grid frequency deviation (49.95Hz). Dispatched kinetic reserves.",
        "Demand peak predicted in 45 mins. Pre-cooling dairy chillers.",
        "Wind speeds exceeding ideal range at Anantapur. Throttling pitch angles.",
        "Optimal solar irradiance detected. Bypassing battery storage to grid.",
        "Hydrogen cell offline for maintenance. Shifted load to Hub B.",
        "Cow DB sync complete. Farm operational metrics normal."
    ];

    // Generate initial logs
    logBox.innerHTML = '';
    for (let i = 0; i < 4; i++) {
        addAILog(logBox, actions[Math.floor(Math.random() * actions.length)], true);
    }

    // Add new log every 8-15 seconds
    aiLogInterval = setInterval(() => {
        addAILog(logBox, actions[Math.floor(Math.random() * actions.length)]);
    }, Math.floor(Math.random() * 7000) + 8000);
}

function addAILog(container, text, isInstant = false) {
    const time = new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
    const entry = document.createElement('div');
    entry.style.cssText = "background: rgba(255,255,255,0.03); border-left: 2px solid var(--primary); padding: 10px; font-size: 0.85rem; border-radius: 4px; opacity: 0; transform: translateX(-10px); transition: all 0.5s ease;";
    entry.innerHTML = `<span style="color:var(--text-2); font-size:0.75rem; margin-right:8px;">[${escapeHtml(time)}]</span> ${escapeHtml(String(text))}`;

    container.prepend(entry);

    // Keep max 10 logs
    if (container.children.length > 10) {
        container.removeChild(container.lastChild);
    }

    // Animate in
    setTimeout(() => {
        entry.style.opacity = '1';
        entry.style.transform = 'translateX(0)';
    }, isInstant ? 0 : 50);
}


// --- PHASE 28: KINETIC STEPS SIMULATION ---
let kineticSimInterval = null;
let currentSteps = 4185292; // Starting seed

function initKineticSimulator() {
    const stepEl = document.getElementById('kinetic-steps');
    if (!stepEl) return;

    // Clear existing
    if (kineticSimInterval) clearInterval(kineticSimInterval);

    // Update the counter with formatting
    const updateDisplay = () => {
        stepEl.innerText = currentSteps.toLocaleString();

        // Add a slight pulse effect to show liveliness
        stepEl.style.transform = 'scale(1.02)';
        stepEl.style.textShadow = '0 0 30px rgba(171, 71, 188, 0.8)';
        setTimeout(() => {
            stepEl.style.transform = 'scale(1)';
            stepEl.style.textShadow = '0 0 20px rgba(171, 71, 188, 0.4)';
        }, 150);
    };

    // Initial draw
    updateDisplay();

    // Simulate real-time hoof steps (adds 20 to 150 steps every 2 seconds)
    kineticSimInterval = setInterval(() => {
        const _newSteps = Math.floor(Math.random() * 130) + 20;
        currentSteps += _newSteps;
        updateDisplay();
    }, 2000);
}


// --- PHASE 29: AGRICULTURE SIMULATIONS ---
let vermiSimInterval = null;

function initVermiSimulators() {
    const tempEl = document.getElementById('bed-temp');
    const moistEl = document.getElementById('bed-moist');
    const wormEl = document.getElementById('worm-density');
    if (!tempEl || !moistEl || !wormEl) return;

    if (vermiSimInterval) clearInterval(vermiSimInterval);

    vermiSimInterval = setInterval(() => {
        // Temperature fluctuates between 22.0 and 23.5 (Optimal<25)
        const tVal = (22.0 + Math.random() * 1.5).toFixed(1);
        tempEl.innerText = tVal + '°C';

        // Moisture fluctuates between 65 and 72%
        const mVal = Math.floor(65 + Math.random() * 7);
        moistEl.innerText = mVal + '%';

        // Worm density naturally fluctuates
        const wVal = Math.floor(15300 + Math.random() * 200).toLocaleString();
        wormEl.innerText = wVal;

    }, 4500); // Check every 4.5s
}


// --- PHASE 30: FACTORY SIMULATIONS (DAIRY & PAINT) ---
let dairyInterval = null;
let paintSimInterval = null;

function initDairySimulators() {
    const pastFlow = document.getElementById('past-flow');
    const bmc1 = document.getElementById('bmc1-temp');
    const bmc2 = document.getElementById('bmc2-temp');
    const bmc3 = document.getElementById('bmc3-temp');

    if (!pastFlow) return;
    if (dairyInterval) clearInterval(dairyInterval);

    dairyInterval = setInterval(() => {
        // Fluctuate Pasteurization Flow (Target ~ 14,250)
        let flow = Math.floor(14150 + Math.random() * 200).toLocaleString();
        if (pastFlow) pastFlow.innerText = flow;

        // Fluctuate BMC temps (Target< 4.0)
        if (bmc1) bmc1.innerText = (3.5 + Math.random() * 0.4).toFixed(1) + '°C';
        if (bmc2) bmc2.innerText = (3.7 + Math.random() * 0.4).toFixed(1) + '°C';
        if (bmc3) bmc3.innerText = (3.6 + Math.random() * 0.4).toFixed(1) + '°C';
    }, 3000);
}

function initPaintSimulators() {
    const voc = document.getElementById('voc-level');
    const dungHop = document.getElementById('paint-hop-dung');

    if (!voc) return;
    if (paintSimInterval) clearInterval(paintSimInterval);

    paintSimInterval = setInterval(() => {
        // Fluctuate VOC levels (Target< 0.5)
        if (voc) voc.innerText = (0.02 + Math.random() * 0.04).toFixed(2);

        // Minor fluctuation on hopper UI text for effect
        if (dungHop && Math.random() > 0.5) {
            let num = parseInt(dungHop.innerText);
            // Slowly drain the hopper
            if (num > 0 && Math.random() > 0.8) {
                dungHop.innerText = (num - 1) + '%';
                dungHop.nextElementSibling.style.height = (num - 1) + '%';
            }
        }
    }, 4000);
}


