document.addEventListener('DOMContentLoaded', () => {

    // 1. Sidebar Toggle
    const sidebarToggle = document.getElementById('sidebarToggle');
    const sidebar = document.querySelector('.sidebar');
    if (sidebarToggle && sidebar) {
        sidebarToggle.addEventListener('click', () => {
            sidebar.classList.toggle('collapsed');
        });
    }

    // 2. Light / Dark Mode Toggle
    // ThemeManager.init() is called in quick_wins.js - no action needed here
    // The onclick="ThemeManager.toggle()" in HTML handles the toggle click

    // 3. System Status & Sync Polling
    const sysDot = document.getElementById('sys-status-dot');
    const sysText = document.getElementById('sys-status-text');
    const syncText = document.getElementById('last-sync-text');

    if (sysText && syncText) {
        setInterval(() => {
            // Flash syncing state
            sysDot.style.background = '#f59e0b';
            sysText.innerText = 'SYNCING...';
            sysText.style.color = '#f59e0b';

            setTimeout(() => {
                sysDot.style.background = '#10b981';
                sysText.innerText = 'SYSTEM ONLINE';
                sysText.style.color = '#10b981';

                // Update timestamp
                const now = new Date();
                syncText.innerText = `Synced: ${now.getHours().toString().padStart(2, '0')}:${now.getMinutes().toString().padStart(2, '0')}:${now.getSeconds().toString().padStart(2, '0')}`;
            }, 1500);

        }, 15000); // Check every 15s
    }

    // 4. Global Fuzzy Search
    const searchInput = document.getElementById('globalSearch');
    if (searchInput) {
        searchInput.addEventListener('keyup', (e) => {
            if (e.key === 'Enter') {
                const term = e.target.value.toLowerCase();
                if (!term) return;

                // Simple DOM search in current view
                const container = document.getElementById('page-container');
                let found = false;

                // Remove old highlights manually by replacing HTML (primitive but works for this demo)
                // In a production app with React/Vue, this state is handled better.

                const walker = document.createTreeWalker(container, NodeFilter.SHOW_TEXT, null, false);
                let node;
                while (node = walker.nextNode()) {
                    if (node.nodeValue.toLowerCase().includes(term) && node.parentNode.tagName !== 'SCRIPT' && node.parentNode.tagName !== 'STYLE') {
                        node.parentNode.classList.add('search-highlight');
                        node.parentNode.scrollIntoView({ behavior: 'smooth', block: 'center' });
                        found = true;

                        setTimeout(() => {
                            node.parentNode.classList.remove('search-highlight');
                        }, 2000);
                        break; // Stop at first find
                    }
                }

                if (!found) {
                    alert(`"${term}"not found on the current screen. Navigate to the relevant module first.`);
                }
            }
        });
    }

});

