// --- HELPER: Populate Cattle Selects ---
async function populateCattleDropdown(selectId, filter = '') {
    const select = document.getElementById(selectId);
    if (!select) return;

    // Fetch cattle and breeds
    const cattle = await insforge.fetch('cattle', filter);
    const breeds = await insforge.fetch('breeds');
    const breedMap = breeds ? Object.fromEntries(breeds.map(b => [b.id, b.name])) : {};

    if (cattle) {
        select.innerHTML = '<option value="">Select Animal...</option>';
        cattle.forEach(c => {
            const opt = document.createElement('option');
            opt.value = c.id;
            const bName = breedMap[c.breed_id] || 'Unknown';
            opt.textContent = `${c.id} - ${c.name} (${bName})`;
            select.appendChild(opt);
        });
    } else {
        select.innerHTML = '<option value="">Error loading cattle</option>';
    }
}

