// --- 2. CATTLE REGISTRY ---
async function initCtRegistry() {
    // A. Load Table
    const [cattle_list, breeds] = await Promise.all([
        insforge.fetch('cattle', '?order=id.asc'),
        insforge.fetch('breeds')
    ]);
    const breedMap = breeds ? Object.fromEntries(breeds.map(b => [b.id, b.name])) : {};

    const tbody = document.getElementById('cattle-registry-body');
    if (tbody && cattle_list) {
        tbody.innerHTML = cattle_list.map(c => `
            <tr>
                <td>${escapeHtml(c.id)}</td>
                <td>${escapeHtml(c.name)}</td>
                <td>${escapeHtml(breedMap[c.breed_id] || 'Unknown')}</td>
                <td>${escapeHtml(c.category)}</td>
                <td>${escapeHtml(c.gender)}</td>
                <td>${escapeHtml(c.status)}</td>
                <td><button type="button"  class="btn-primary" style="padding: 2px 8px; font-size: 0.7rem;">Edit</button></td>
            </tr>
        `).join('');
    }

    // A.1 Populate Breed Dropdown in form
    const breedSelect = document.getElementById('reg-breed-select');
    if (breedSelect && breeds) {
        breedSelect.innerHTML = breeds.map(b => `<option value="${escapeHtml(b.id)}">${escapeHtml(b.name)}</option>`).join('');
    }

    // B. Handle Form
    const form = document.getElementById('cattle-reg-form');
    if (form) {
        form.onsubmit = async (e) => {
            e.preventDefault();
            const formData = new FormData(form);
            const data = Object.fromEntries(formData.entries());
            const res = await insforge.insert('cattle', data);
            if (res) {
                alert('Success: Cattle registered!');
                initCtRegistry();
                form.reset();
            }
        };
    }
}

// --- 3. MILK MANAGEMENT ---
async function initCtMilk() {
    // A. Form: Record Yield (Batch Entry)
    const cattle = await insforge.fetch('cattle', '?category=eq.Milking&order=id.asc');
    const tbody = document.getElementById('milk-entry-rows');
    if (tbody && cattle) {
        tbody.innerHTML = cattle.map(c => `
            <tr>
                <td>${escapeHtml(c.id)}</td>
                <td>${escapeHtml(c.name)}</td>
                <td><input type="number" class="liters-in" data-cid="${escapeHtml(c.id)}" step="0.1" style="width:60px;"></td>
                <td><input type="number" class="fat-in" data-cid="${escapeHtml(c.id)}" step="0.1" style="width:50px;"></td>
                <td><input type="number" class="snf-in" data-cid="${escapeHtml(c.id)}" step="0.1" style="width:50px;"></td>
                <td><input type="number" class="protein-in" data-cid="${escapeHtml(c.id)}" step="0.1" style="width:50px;"></td>
                <td><input type="number" class="lacto-in" data-cid="${escapeHtml(c.id)}" step="0.1" style="width:50px;"></td>
                <td><input type="number" class="temp-in" data-cid="${escapeHtml(c.id)}" step="0.1" style="width:50px;" value="38.5"></td>
                <td><select class="quality-in" data-cid="${escapeHtml(c.id)}"><option value="A">A</option><option value="B">B</option><option value="Reject">Reject</option></select></td>
            </tr>
        `).join('');
    }

    const yieldForm = document.getElementById('milk-entry-form');
    if (yieldForm) {
        yieldForm.onsubmit = async (e) => {
            e.preventDefault();
            const date = document.getElementById('milk-date-input').value;
            const session = yieldForm.session.value;

            const rows = [];
            const literInputs = yieldForm.querySelectorAll('.liters-in');
            literInputs.forEach(inp => {
                const liters = parseFloat(inp.value);
                if (liters > 0) {
                    const cid = inp.dataset.cid;
                    const fat = parseFloat(yieldForm.querySelector(`.fat-in[data-cid="${cid}"]`).value || 0);
                    const snf = parseFloat(yieldForm.querySelector(`.snf-in[data-cid="${cid}"]`).value || 0);
                    const protein = parseFloat(yieldForm.querySelector(`.protein-in[data-cid="${cid}"]`).value || 0);
                    const lacto = parseFloat(yieldForm.querySelector(`.lacto-in[data-cid="${cid}"]`).value || 0);
                    const temp = parseFloat(yieldForm.querySelector(`.temp-in[data-cid="${cid}"]`).value || 0);
                    const grade = yieldForm.querySelector(`.quality-in[data-cid="${cid}"]`).value;
                    rows.push({
                        cattle_id: cid,
                        record_date: date,
                        session: session,
                        liters: liters,
                        fat_percentage: fat,
                        snf_pct: snf,
                        protein_pct: protein,
                        lactometer: lacto,
                        temp_c: temp,
                        quality_grade: grade
                    });
                }
            });

            if (rows.length === 0) return alert('Enter at least one yield!');

            // Multiple inserts
            let count = 0;
            for (const row of rows) {
                if (await insforge.insert('milk_records', row)) count++;
            }
            alert(`Success: ${count} records saved!`);
            yieldForm.reset();
        };
    }

    // B. Form: Record Sale
    const saleForm = document.getElementById('milk-sales-form');
    if (saleForm) {
        const qtyIn = document.getElementById('sale-qty');
        const rateIn = document.getElementById('sale-rate');
        const totalIn = document.getElementById('sale-total');

        const calcTotal = () => { totalIn.value = (parseFloat(qtyIn.value || 0) * parseFloat(rateIn.value || 0)).toFixed(2); };
        if (qtyIn) qtyIn.oninput = calcTotal;
        if (rateIn) rateIn.oninput = calcTotal;

        saleForm.onsubmit = async (e) => {
            e.preventDefault();
            const formData = new FormData(saleForm);
            const data = Object.fromEntries(formData.entries());
            // Map total_amount for schema (it was calculated display only)
            data.total_amount = totalIn.value;

            const res = await insforge.insert('milk_sales', data);
            if (res) { alert('Sale Recorded!'); saleForm.reset(); totalIn.value = ''; }
        };
    }
}

