/**
 * Generic handler for Hub forms
 */
function handleHubForm(formId, tableName, successMsg, callback) {
    const form = document.getElementById(formId);
    if (!form) return;

    form.onsubmit = async (e) => {
        e.preventDefault();
        const formData = new FormData(form);
        const data = Object.fromEntries(formData.entries());

        // Basic numeric conversion for all fields
        for (let key in data) {
            if (data[key] && !isNaN(data[key]) && data[key].trim() !== '') {
                data[key] = Number(data[key]);
            }
        }

        const result = await insforge.insert(tableName, data);
        if (result) {
            alert(successMsg || 'Data saved successfully!');
            form.reset();
            if (callback) callback(result);
        } else {
            alert('Error saving data. Please check connection or schema.');
        }
    };
}

/**
 * Populate a dropdown with data from an InsForge table
 */
async function populateHubDropdown(selectId, tableName, textField, valueField = 'id') {
    const select = document.getElementById(selectId);
    if (!select) return;

    const items = await insforge.fetch(tableName);
    if (items && items.length > 0) {
        select.innerHTML = '<option value="">Select Option...</option>';
        items.forEach(item => {
            const opt = document.createElement('option');
            opt.value = item[valueField];
            opt.textContent = item[textField];
            select.appendChild(opt);
        });
    } else {
        select.innerHTML = '<option value="">No data found</option>';
    }
}

