async function fetchPharmaInventory() {
    const list = document.getElementById('pharma-inventory-body');
    if (!list) return;
    list.innerHTML = '<tr><td colspan="6" style="text-align:center;">Loading Inventory...</td></tr>';

    // Fetch inventory from InsForge
    const items = await window.insforge.fetch('vet_pharma_inventory', '?order=id.asc');
    if (!items) return;

    let html = '';
    let totalStock = 0;
    let lowCount = 0;
    let expCount = 0;

    items.forEach(i => {
        totalStock++;
        let isLow = i.stock < i.min_req;
        let pClass = 'pill-green';
        if (isLow || i.status.includes('Low')) pClass = 'pill-red';
        else if (i.status.includes('Expiring')) pClass = 'pill-red';
        else if (i.status.includes('amber') || i.status === 'Low') pClass = 'pill-amber';

        if (isLow) lowCount++;
        if (pClass === 'pill-red' && !isLow) expCount++;

        html += `<tr>
            <td>${i.medicine_name}</td>
            <td>${i.category}</td>
            <td>${i.stock}</td>
            <td>${i.min_req}</td>
            <td>${i.expiry_date || 'N/A'}</td>
            <td><span class="pill ${pClass}">${i.status}</span></td>
        </tr>`;
    });

    list.innerHTML = html;

    const kpi = document.getElementById('pharma-kpi-grid');
    if (kpi) {
        let stockHealth = Math.max(0, 100 - (lowCount * 5));
        kpi.innerHTML = `
           <div class="kpi-card green"><div class="kpi-top"><div class="kpi-icon">💊</div></div><div><div class="kpi-value">${stockHealth}%</div><div class="kpi-label">Overall Stock Level</div></div></div>
           <div class="kpi-card orange"><div class="kpi-top"><div class="kpi-icon">⚠️</div></div><div><div class="kpi-value">${lowCount}</div><div class="kpi-label">Low Stock Items</div></div></div>
           <div class="kpi-card red"><div class="kpi-top"><div class="kpi-icon">⏰</div></div><div><div class="kpi-value">${expCount}</div><div class="kpi-label">Expiring Soon</div></div></div>
        `;
    }
}

async function generateOutbreakMap() {
    const grid = document.getElementById('quar-outbreak-grid');
    if (!grid) return;

    // Fetch critical cases 
    const cases = await window.insforge.fetch('vet_cases', '?status=eq.critical');
    if (!cases) return;

    let html = '';
    let infCount = 0;
    let totalQ = cases.length;

    cases.forEach(c => {
        infCount++;
        let reason = c.diagnosis || 'Suspected Infection';
        html += `<div class="quar-card"><div class="quar-card-header"><div class="quar-id">#${c.rfid || ('GID-' + c.id)}</div><span class="pill pill-red">Infectious</span></div><div class="quar-reason">${reason}</div><div class="quar-days">Bed: ${c.bed_id || 'N/A'} · Zone: ${c.zone || 'Bellary'}</div></div>`;
    });

    if (cases.length === 0) {
        html = '<div style="padding: 2rem; width: 100%; text-align: center; color: var(--success);">✅ No active infectious outbreaks detected across zones.</div>';
    }

    grid.innerHTML = html;

    const kpi = document.getElementById('quar-kpi-grid');
    if (kpi) {
        kpi.innerHTML = `
           <div class="kpi-card red"><div class="kpi-top"><div class="kpi-icon">⚠️</div></div><div><div class="kpi-value">${totalQ}</div><div class="kpi-label">Critical Ward Cases</div></div></div>
           <div class="kpi-card orange"><div class="kpi-top"><div class="kpi-icon">🦠</div></div><div><div class="kpi-value">${infCount}</div><div class="kpi-label">Confirmed Infectious</div></div></div>
        `;
    }
}


