async function initWaterHub() {
    const wrap = document.getElementById('hydro-reservoir-wrap');
    if (!wrap) return;
    wrap.innerHTML = '<div style="padding:1rem;text-align:center;">Querying Reservoir IoT Levels...</div>';

    const items = await window.insforge.fetch('hydro_reservoirs', '');
    if (!items) return;

    let html = '';

    items.forEach(i => {
        let pct = Math.round((i.current_level_ml / i.capacity_ml) * 100) || 0;
        let color = '#00b0ff';
        if (pct < 30) color = '#ff3d00';
        else if (pct < 50) color = '#ffc107';

        let displayLevel = (i.current_level_ml / 1000).toFixed(1) + 'k ML';

        html += `<div class="silo-row">
            <div class="silo-label">${i.name}</div>
            <div class="silo-bar-bg"><div class="silo-fill" style="width:${pct}%;background:${color};"></div></div>
            <div class="silo-val">${displayLevel} (${pct}%)</div>
        </div>`;
    });

    wrap.innerHTML = html;
}


