window.poultryTab = function (paneId, btn) {

    document.querySelectorAll('#poultry-hub .dairy-pane').forEach(p => p.classList.remove('active'));
    document.querySelectorAll('#poultry-hub .dairy-tab-btn').forEach(b => b.classList.remove('active'));
    document.getElementById('p-' + paneId).classList.add('active');
    btn.classList.add('active');
}

window.initPoultryHubEnterprise = async function () {

    console.log("Initializing Deep Entity Poultry Hub...");
    if (!window.insforge) {
        console.warn("InsForge not initialized, skipping Poultry sync.");
        return;
    }

    try {
        // 1. Fetch KPI Rollups
        const birds = await window.insforge.fetch('poultry_batches', '?select=initial_birds,status');
        let totalBirds = 0; let activeBatches = 0;
        if (birds) {
            birds.forEach(b => {
                if (b.status === 'Active') {
                    totalBirds += (b.initial_birds || 0);
                    activeBatches++;
                }
            });
        }
        var _el_p_kpi_birds = document.getElementById('p-kpi-birds'); if (_el_p_kpi_birds) _el_p_kpi_birds.innerText = totalBirds.toLocaleString();
        var _el_p_kpi_batches = document.getElementById('p-kpi-batches'); if (_el_p_kpi_batches) _el_p_kpi_batches.innerText = activeBatches;

        const sheds = await window.insforge.fetch('poultry_sheds', '?select=id');
        var _el_p_kpi_sheds = document.getElementById('p-kpi-sheds'); if (_el_p_kpi_sheds) _el_p_kpi_sheds.innerText = sheds ? sheds.length : 0;

        // Today's Date String
        const today = new Date().toISOString().split('T')[0];

        // Today's Eggs
        const eggs = await window.insforge.fetch('poultry_daily_egg_collection', `?record_date=eq.${today}`);
        let dailyEggs = 0;
        if (eggs) eggs.forEach(e => dailyEggs += (e.good_eggs || 0));
        var _el_p_kpi_eggs = document.getElementById('p-kpi-eggs'); if (_el_p_kpi_eggs) _el_p_kpi_eggs.innerText = dailyEggs.toLocaleString();

        // Today's Feed
        const feed = await window.insforge.fetch('poultry_daily_feed', `?record_date=eq.${today}`);
        let dailyFeed = 0;
        if (feed) feed.forEach(f => dailyFeed += (f.qty_given_kg || 0));
        var _el_p_kpi_feed = document.getElementById('p-kpi-feed'); if (_el_p_kpi_feed) _el_p_kpi_feed.innerText = dailyFeed.toLocaleString() + ' Kg';

        // Today's Mortality
        const dead = await window.insforge.fetch('poultry_daily_mortality', `?record_date=eq.${today}`);
        let dailyDead = 0;
        if (dead) dead.forEach(d => dailyDead += (d.dead_count || 0));
        var _el_p_kpi_dead = document.getElementById('p-kpi-dead'); if (_el_p_kpi_dead) _el_p_kpi_dead.innerText = dailyDead.toLocaleString();

        // Financials Today
        const inc = await window.insforge.fetch('poultry_income', `?date=eq.${today}`);
        let todayRev = 0;
        if (inc) inc.forEach(i => todayRev += (i.amount || 0));
        var _el_p_kpi_rev = document.getElementById('p-kpi-rev'); if (_el_p_kpi_rev) _el_p_kpi_rev.innerText = '₹' + todayRev.toLocaleString();

        const exp = await window.insforge.fetch('poultry_expenses', `?date=eq.${today}`);
        let todayExp = 0;
        if (exp) exp.forEach(e => todayExp += (e.amount || 0));
        var _el_p_kpi_exp = document.getElementById('p-kpi-exp'); if (_el_p_kpi_exp) _el_p_kpi_exp.innerText = '₹' + todayExp.toLocaleString();

        // Load Alerts
        const alerts = await window.insforge.fetch('poultry_notifications', '?limit=5&order=created_at.desc');
        let alHTML = '';
        if (alerts && alerts.length > 0) {
            alerts.forEach(a => {
                alHTML += `<div style="padding:10px; border-bottom:1px solid rgba(255,255,255,0.1); display:flex; gap:10px;">
                    <div>⚠️</div><div><div><strong>${a.alert_type}</strong></div><div style="font-size:0.85rem; color:var(--text-muted);">${a.message}</div></div></div>`;
            });
        } else {
            alHTML = '<div style="padding:10px; color:var(--text-muted);">No critical alerts today.</div>';
        }
        var _el_p_dash_alerts = document.getElementById('p-dash-alerts'); if (_el_p_dash_alerts) _el_p_dash_alerts.innerHTML = alHTML;

        // Populate Select Dropdowns
        populatePoultrySelects();
        loadPoultryTables();

    } catch (err) {
        console.error("Failed Poultry Init:", err);
    }
}

async function populatePoultrySelects() {
    try {
        const sheds = await window.insforge.fetch('poultry_sheds', '');
        let sHTML = '<option value="">Select Shed...</option>';
        if (sheds) sheds.forEach(s => sHTML += `<option value="${s.id}">${s.shed_name}</option>`);
        var _el_pb_shed = document.getElementById('pb-shed'); if (_el_pb_shed) _el_pb_shed.innerHTML = sHTML;
        var _el_ps_shed = document.getElementById('ps-shed'); if (_el_ps_shed) _el_ps_shed.innerHTML = sHTML;

        const batches = await window.insforge.fetch('poultry_batches', '?status=eq.Active');
        let bHTML = '<option value="">Select Batch...</option>';
        let bLayer = '<option value="">Select Layer Batch...</option>';
        let bBroil = '<option value="">Select Broiler Batch...</option>';

        if (batches) {
            batches.forEach(b => {
                bHTML += `<option value="${b.id}">${b.batch_id} - ${b.batch_name}</option>`;
                if (b.bird_type === 'Layer') bLayer += `<option value="${b.id}">${b.batch_id} - ${b.batch_name}</option>`;
                if (b.bird_type === 'Broiler') bBroil += `<option value="${b.id}">${b.batch_id} - ${b.batch_name}</option>`;
            });
        }
        var _el_pe_batch = document.getElementById('pe-batch'); if (_el_pe_batch) _el_pe_batch.innerHTML = bLayer;
        var _el_pm_batch = document.getElementById('pm-batch'); if (_el_pm_batch) _el_pm_batch.innerHTML = bBroil;
        var _el_ph_m_batch = document.getElementById('ph-m-batch'); if (_el_ph_m_batch) _el_ph_m_batch.innerHTML = bHTML;
        var _el_ph_v_batch = document.getElementById('ph-v-batch'); if (_el_ph_v_batch) _el_ph_v_batch.innerHTML = bHTML;
        var _el_pf_batch = document.getElementById('pf-batch'); if (_el_pf_batch) _el_pf_batch.innerHTML = bHTML;

        const feeds = await window.insforge.fetch('poultry_feed_inventory', '');
        let fHTML = '<option value="">Select Feed Type...</option>';
        if (feeds) feeds.forEach(f => fHTML += `<option value="${f.id}">${f.feed_name}</option>`);
        var _el_pf_feed = document.getElementById('pf-feed'); if (_el_pf_feed) _el_pf_feed.innerHTML = fHTML;

    } catch (e) { console.error(e) }
}

async function loadPoultryTables() {
    try {
        // Load Batch List
        const b = await window.insforge.fetch('poultry_batches', '?select=*,poultry_sheds(shed_name)&order=id.desc');
        let btrs = '';
        if (b) b.forEach(x => {
            btrs += `<tr><td>${x.batch_id}</td><td>${x.bird_type}</td><td>-</td><td>${x.initial_birds}</td><td>${x.poultry_sheds?.shed_name || 'N/A'}</td><td><span style="color:var(--neon-green)">${x.status}</span></td></tr>`;
        });
        var _el_p_batch_list = document.getElementById('p-batch-list'); if (_el_p_batch_list) _el_p_batch_list.innerHTML = btrs || '<tr><td colspan="6">No Active Batches</td></tr>';

        // Load Egg History
        const e = await window.insforge.fetch('poultry_daily_egg_collection', '?select=*,poultry_batches(batch_id)&limit=10&order=record_date.desc');
        let etrs = '';
        if (e) e.forEach(x => {
            etrs += `<tr><td>${x.record_date}</td><td>${x.session_time}</td><td>${x.poultry_batches?.batch_id || 'N/A'}</td><td>${x.good_eggs}</td><td>-</td></tr>`;
        });
        var _el_p_egg_history = document.getElementById('p-egg-history'); if (_el_p_egg_history) _el_p_egg_history.innerHTML = etrs || '<tr><td colspan="5">No Records</td></tr>';

        // Load Mortality History
        const m = await window.insforge.fetch('poultry_daily_mortality', '?select=*,poultry_batches(batch_id)&limit=10&order=record_date.desc');
        let mtrs = '';
        if (m) m.forEach(x => {
            mtrs += `<tr><td>${x.record_date}</td><td><span style="color:var(--red)">Mortality</span></td><td>${x.poultry_batches?.batch_id || 'N/A'}</td><td>${x.dead_count} dead (${x.suspected_cause})</td></tr>`;
        });
        var _el_p_health_history = document.getElementById('p-health-history'); if (_el_p_health_history) _el_p_health_history.innerHTML = mtrs || '<tr><td colspan="4">No Records</td></tr>';

    } catch (e) { console.error(e) }
}



