// POULTRY HUB: FLOCK & BATCH MANAGEMENT (PHASE 39)
// ==========================================

async function savePoultryBatch() {
    console.log("Saving new poultry batch...");
    if (!window.insforge) return alert("InsForge not initialized.");

    const name = document.getElementById('pb-name').value;
    const type = document.getElementById('pb-type').value;
    const date = document.getElementById('pb-date').value;
    const count = parseInt(document.getElementById('pb-count').value);
    const shed = parseInt(document.getElementById('pb-shed').value);
    const hatchery = document.getElementById('pb-hatchery').value;
    const cost = parseFloat(document.getElementById('pb-cost').value);

    if (!name || !date || !count || !shed) return alert("Please fill required fields: Name, Date, Count, Shed.");

    // Auto-generate Batch ID
    const rando = Math.floor(Math.random() * 1000).toString().padStart(3, '0');
    const bId = type.substring(0, 1).toUpperCase() + '-' + rando;

    try {
        const payload = {
            batch_id: bId,
            batch_name: name,
            bird_type: type,
            placement_date: date,
            initial_birds: count,
            source_hatchery: hatchery,
            cost_per_chick: cost,
            shed_id: shed,
            status: 'Active'
        };

        const res = await window.insforge.insert('poultry_batches', [payload]);
        if (res && !res.error) {
            alert(`Batch ${bId} registered successfully!`);
            // Clear form
            document.getElementById('pb-name').value = '';
            document.getElementById('pb-count').value = '';
            document.getElementById('pb-hatchery').value = '';
            document.getElementById('pb-cost').value = '';
            // Refresh tables and selects
            populatePoultrySelects();
            loadPoultryTables();
            initPoultryHubEnterprise(); // Refresh KPIs
        } else {
            alert("Error saving batch: " + JSON.stringify(res.error || res));
            console.error(res);
        }
    } catch (e) {
        console.error("Batch save error:", e);
        alert("Exception saving batch. See console.");
    }
}


// ==========================================
// POULTRY HUB: EGG MANAGEMENT (PHASE 40)
// ==========================================

async function saveEggCollection() {
    console.log("Saving egg collection...");
    if (!window.insforge) return alert("InsForge not initialized.");

    const date = document.getElementById('pe-date').value;
    const batchId = document.getElementById('pe-batch').value;
    const session = document.getElementById('pe-session').value;
    const good = parseInt(document.getElementById('pe-good').value) || 0;
    const broken = parseInt(document.getElementById('pe-broken').value) || 0;
    const dirty = parseInt(document.getElementById('pe-dirty').value) || 0;
    const weight = parseFloat(document.getElementById('pe-weight').value) || 0;

    if (!date || !batchId || good === 0) return alert("Please fill Date, Batch, and Good Eggs count.");

    try {
        // Fetch current batch details to get shed_id and live bird count for HDP%
        const bInfo = await window.insforge.fetch('poultry_batches', `?id=eq.${batchId}&select=shed_id,initial_birds`);
        const shedId = bInfo && bInfo.length > 0 ? bInfo[0].shed_id : null;

        let hdp = 0;
        if (bInfo && bInfo[0].initial_birds > 0) {
            hdp = ((good + broken + dirty) / bInfo[0].initial_birds) * 100;
        }

        const payload = {
            record_date: date,
            batch_id: parseInt(batchId),
            shed_id: shedId,
            session_time: session,
            good_eggs: good,
            broken_eggs: broken,
            dirty_eggs: dirty,
            avg_egg_weight: weight,
            collector_name: 'Admin'
        };

        const res = await window.insforge.insert('poultry_daily_egg_collection', [payload]);
        if (res && !res.error) {
            // Also update Egg Inventory (Trays)
            const trays = Math.floor(good / 30);
            await window.insforge.insert('poultry_egg_inventory', [{
                record_date: date,
                stock_in_trays: trays,
                stock_out_trays: 0,
                wastage_trays: 0,
                current_stock_trays: trays // Simplified for MVP
            }]);

            alert(`Saved ${good} eggs. HDP: ${hdp.toFixed(1)}%`);
            document.getElementById('pe-good').value = '';
            document.getElementById('pe-broken').value = '';
            document.getElementById('pe-weight').value = '';

            // Re-fetch tables to show new data
            loadPoultryTables();
            initPoultryHubEnterprise();

            // Update local UI
            var _el_pe_hdp = document.getElementById('pe-hdp'); if (_el_pe_hdp) _el_pe_hdp.innerText = hdp.toFixed(1) + '%';
        } else {
            alert("Error saving eggs.");
            console.error(res);
        }
    } catch (err) { console.error(err); alert("Exception saving eggs."); }
}


// ==========================================
// POULTRY HUB: BROILER MANAGEMENT (PHASE 41)
// ==========================================

async function saveBroilerWeight() {
    console.log("Saving broiler weight...");
    if (!window.insforge) return alert("InsForge not initialized.");

    const date = document.getElementById('pm-date').value;
    const batchId = document.getElementById('pm-batch').value;
    const sample = parseInt(document.getElementById('pm-sample').value) || 0;
    const weight = parseFloat(document.getElementById('pm-weight').value) || 0;
    const uniformity = parseFloat(document.getElementById('pm-uniformity').value) || 0;

    if (!date || !batchId || weight === 0) return alert("Please fill Date, Batch, and Avg Weight.");

    try {
        const payload = {
            record_date: date,
            batch_id: parseInt(batchId),
            sample_size: sample,
            avg_weight_g: weight,
            uniformity_pct: uniformity
        };

        const res = await window.insforge.insert('poultry_body_weight', [payload]);
        if (res && !res.error) {

            // Recalculate FCR (Simple approximation: Total Feed / Total Weight Gained)
            // Fetch total feed mapped to this batch
            const feeds = await window.insforge.fetch('poultry_daily_feed', `?batch_id=eq.${batchId}`);
            let tf = 0;
            if (feeds) feeds.forEach(f => tf += (f.qty_given_kg || 0));

            // Fetch initial birds to find total weight
            const bInfo = await window.insforge.fetch('poultry_batches', `?id=eq.${batchId}&select=initial_birds`);
            let fcr = 0;
            if (bInfo && bInfo[0].initial_birds > 0 && weight > 0) {
                const totalWeightGainedKg = (bInfo[0].initial_birds * weight) / 1000;
                if (totalWeightGainedKg > 0) fcr = tf / totalWeightGainedKg;
            }

            alert(`Saved Weight! FCR calculated at: ${fcr.toFixed(2)}`);
            document.getElementById('pm-weight').value = '';
            var _el_pm_fcr = document.getElementById('pm-fcr'); if (_el_pm_fcr) _el_pm_fcr.innerText = fcr.toFixed(2);

        } else {
            alert("Error saving weight.");
            console.error(res);
        }
    } catch (err) { console.error(err); alert("Exception saving weight."); }
}


