async function savePoultryFeed() {
    console.log("Saving daily feed...");
    if (!window.insforge) return alert("InsForge not initialized.");

    const date = document.getElementById('pf-date').value;
    const batchId = document.getElementById('pf-batch').value;
    const feedId = document.getElementById('pf-feed').value;
    const qty = parseFloat(document.getElementById('pf-qty').value) || 0;
    const wasted = parseFloat(document.getElementById('pf-wasted').value) || 0;

    if (!date || !batchId || !feedId || qty === 0) return alert("Please fill Date, Batch, Feed Type, and Quantity.");

    try {
        const payload = {
            record_date: date,
            batch_id: parseInt(batchId),
            feed_id: parseInt(feedId),
            qty_given_kg: qty,
            qty_wasted_kg: wasted
        };

        const res = await window.insforge.insert('poultry_daily_feed', [payload]);
        if (res && !res.error) {

            // Check Live Birds to calculate g/bird
            const bInfo = await window.insforge.fetch('poultry_batches', `?id=eq.${batchId}&select=initial_birds`);
            let pBird = 0;
            if (bInfo && bInfo[0].initial_birds > 0) {
                pBird = ((qty - wasted) * 1000) / bInfo[0].initial_birds;
            }

            alert(`Saved! Intake: ${pBird.toFixed(1)} g/bird.`);
            document.getElementById('pf-qty').value = '';
            document.getElementById('pf-wasted').value = '';
            var _el_pf_avg_feed = document.getElementById('pf-avg-feed'); if (_el_pf_avg_feed) _el_pf_avg_feed.innerText = pBird.toFixed(1) + ' g';

            loadPoultryTables();
            initPoultryHubEnterprise();
        } else {
            alert("Error saving feed.");
            console.error(res);
        }
    } catch (err) { console.error(err); alert("Exception saving feed."); }
}

async function savePoultryWater() {
    console.log("Saving daily water...");
    if (!window.insforge) return alert("InsForge not initialized.");

    const date = document.getElementById('pf-date').value;
    const batchId = document.getElementById('pf-batch').value;
    const water = parseFloat(document.getElementById('pf-water').value) || 0;

    if (!date || !batchId || water === 0) return alert("Please fill Date, Batch, and Water Quantity.");

    try {
        const payload = {
            record_date: date,
            batch_id: parseInt(batchId),
            water_used_liters: water
        };

        const res = await window.insforge.insert('poultry_daily_water', [payload]);
        if (res && !res.error) {

            // Re-fetch today's feed to calculate ratio
            const feeds = await window.insforge.fetch('poultry_daily_feed', `?batch_id=eq.${batchId}&record_date=eq.${date}`);
            let ratio = "N/A";
            if (feeds && feeds.length > 0) {
                const totalFeed = feeds.reduce((sum, f) => sum + (f.qty_given_kg - f.qty_wasted_kg), 0);
                if (totalFeed > 0) {
                    ratio = `1:${(water / totalFeed).toFixed(2)}`;
                }
            }

            alert(`Water saved. Water:Feed Ratio is ${ratio}`);
            document.getElementById('pf-water').value = '';
            var _el_pf_ratio = document.getElementById('pf-ratio'); if (_el_pf_ratio) _el_pf_ratio.innerText = ratio;

        } else {
            alert("Error saving water.");
            console.error(res);
        }
    } catch (err) { console.error(err); alert("Exception saving water."); }
}


