async function savePoultryEnv() {
    console.log("Saving env reading...");
    if (!window.insforge) return alert("InsForge not initialized.");

    const shedId = document.getElementById('ps-shed').value;
    const temp = parseFloat(document.getElementById('ps-temp').value) || 0;
    const hum = parseFloat(document.getElementById('ps-hum').value) || 0;
    const amm = parseFloat(document.getElementById('ps-amm').value) || 0;
    const fans = parseInt(document.getElementById('ps-fans').value) || 0;

    if (!shedId) return alert("Please select a Shed.");

    // Auto-generate Date and Time
    const now = new Date();
    const date = now.toISOString().split('T')[0];
    const time = now.toTimeString().split(' ')[0]; // HH:MM:SS

    try {
        const payload = {
            record_date: date,
            record_time: time,
            shed_id: parseInt(shedId),
            temperature_c: temp,
            humidity_pct: hum,
            ammonia_ppm: amm,
            fans_running: fans
        };

        const res = await window.insforge.insert('poultry_environment_log', [payload]);
        if (res && !res.error) {
            alert(`Environment logged for Shed ${shedId}.`);
            document.getElementById('ps-temp').value = '';
            document.getElementById('ps-hum').value = '';
            document.getElementById('ps-amm').value = '';

            // Generate Alerts if out of range (Simulated Trigger)
            if (temp > 32) generatePoultryAlert(`Temperature Critical: ${temp}°C in Shed ${shedId}`);
            if (amm > 25) generatePoultryAlert(`Ammonia Critical: ${amm}ppm in Shed ${shedId}`);

            loadPoultryTables();
        } else {
            alert("Error saving env reading.");
            console.error(res);
        }
    } catch (err) { console.error(err); alert("Exception saving env."); }
}

