// 12. ENTERPRISE POULTRY HUB (PHASES 38-50)
// ==========================================

function poultryTab(paneId, btn) {
    document.querySelectorAll('#poultry-hub .dairy-pane').forEach(p => p.classList.remove('active'));
    document.querySelectorAll('#poultry-hub .dairy-tab-btn').forEach(b => b.classList.remove('active'));
    document.getElementById('p-' + paneId).classList.add('active');
    btn.classList.add('active');
}

window.initPoultryHubEnterprise = async function () {

    console.log("Initializing Deep Entity Poultry Hub...");
    if (!window.insforge) {
        console.warn("InsForge not initialized, skipping Poultry sync.");
        return;
    }

    try {
        // 1. Fetch KPI Rollups
        const birds = await window.insforge.fetch('poultry_batches', '?select=initial_birds,status');
        let totalBirds = 0; let activeBatches = 0;
        if (birds) {
            birds.forEach(b => {
                if (b.status === 'Active') {
                    totalBirds += (b.initial_birds || 0);
                    activeBatches++;
                }
            });
        }
        var _el_p_kpi_birds = document.getElementById('p-kpi-birds'); if (_el_p_kpi_birds) _el_p_kpi_birds.innerText = totalBirds.toLocaleString();
        var _el_p_kpi_batches = document.getElementById('p-kpi-batches'); if (_el_p_kpi_batches) _el_p_kpi_batches.innerText = activeBatches;

        const sheds = await window.insforge.fetch('poultry_sheds', '?select=id');
        var _el_p_kpi_sheds = document.getElementById('p-kpi-sheds'); if (_el_p_kpi_sheds) _el_p_kpi_sheds.innerText = sheds ? sheds.length : 0;

        // Today's Date String
        const today = new Date().toISOString().split('T')[0];

        // Today's Eggs
        const eggs = await window.insforge.fetch('poultry_daily_egg_collection', `?record_date=eq.${today}`);
        let dailyEggs = 0;
        if (eggs) eggs.forEach(e => dailyEggs += (e.good_eggs || 0));
        var _el_p_kpi_eggs = document.getElementById('p-kpi-eggs'); if (_el_p_kpi_eggs) _el_p_kpi_eggs.innerText = dailyEggs.toLocaleString();

        // Today's Feed
        const feed = await window.insforge.fetch('poultry_daily_feed', `?record_date=eq.${today}`);
        let dailyFeed = 0;
        if (feed) feed.forEach(f => dailyFeed += (f.qty_given_kg || 0));
        var _el_p_kpi_feed = document.getElementById('p-kpi-feed'); if (_el_p_kpi_feed) _el_p_kpi_feed.innerText = dailyFeed.toLocaleString() + ' Kg';

        // Today's Mortality
        const dead = await window.insforge.fetch('poultry_daily_mortality', `?record_date=eq.${today}`);
        let dailyDead = 0;
        if (dead) dead.forEach(d => dailyDead += (d.dead_count || 0));
        var _el_p_kpi_dead = document.getElementById('p-kpi-dead'); if (_el_p_kpi_dead) _el_p_kpi_dead.innerText = dailyDead.toLocaleString();

        // Financials Today
        const inc = await window.insforge.fetch('poultry_income', `?date=eq.${today}`);
        let todayRev = 0;
        if (inc) inc.forEach(i => todayRev += (i.amount || 0));
        var _el_p_kpi_rev = document.getElementById('p-kpi-rev'); if (_el_p_kpi_rev) _el_p_kpi_rev.innerText = '₹' + todayRev.toLocaleString();

        const exp = await window.insforge.fetch('poultry_expenses', `?date=eq.${today}`);
        let todayExp = 0;
        if (exp) exp.forEach(e => todayExp += (e.amount || 0));
        var _el_p_kpi_exp = document.getElementById('p-kpi-exp'); if (_el_p_kpi_exp) _el_p_kpi_exp.innerText = '₹' + todayExp.toLocaleString();

        // Load Alerts
        const alerts = await window.insforge.fetch('poultry_notifications', '?limit=5&order=created_at.desc');
        let alHTML = '';
        if (alerts && alerts.length > 0) {
            alerts.forEach(a => {
                alHTML += `<div style="padding:10px; border-bottom:1px solid rgba(255,255,255,0.1); display:flex; gap:10px;">
                    <div>⚠️</div><div><div><strong>${a.alert_type}</strong></div><div style="font-size:0.85rem; color:var(--text-muted);">${a.message}</div></div></div>`;
            });
        } else {
            alHTML = '<div style="padding:10px; color:var(--text-muted);">No critical alerts today.</div>';
        }
        var _el_p_dash_alerts = document.getElementById('p-dash-alerts'); if (_el_p_dash_alerts) _el_p_dash_alerts.innerHTML = alHTML;

        // Populate Select Dropdowns
        populatePoultrySelects();
        loadPoultryTables();

    } catch (err) {
        console.error("Failed Poultry Init:", err);
    }
}




