async function initAquaHubEnterprise() {
    console.log("Initializing Deep Entity Aquaculture Hub...");

    // Wire up navigation clicks (legacy aq-nav-list, replaced by dairy-nav)
    // Removed because we are now using aqTab() for horizontal navigation directly bound via onclick.

    if (!window.insforge) {
        console.warn("InsForge not initialized, skipping Aqua sync.");
        return;
    }

    try {
        // Run specific dashboard refresh algorithms
        if (typeof refreshAquaDashboard === 'function') refreshAquaDashboard();

        // Fetch KPI Rollups
        const ponds = await window.insforge.fetch('aqua_ponds', '?select=id,status');
        let activePonds = 0;
        if (ponds && !ponds.error) {
            ponds.forEach(p => {
                if (p.status === 'Active') activePonds++;
            });
            const pLabel = document.getElementById('kpi-aq-ponds');
            if (pLabel) pLabel.innerText = activePonds + " active";
        }

        // Fetch Total Stocking Count
        const stocking = await window.insforge.fetch('aqua_stocking_records', '?select=stock_count');
        let totalFish = 0;
        if (stocking && !stocking.error) {
            stocking.forEach(s => totalFish += parseInt(s.stock_count || 0));
            const fLabel = document.getElementById('kpi-aq-fish');
            if (fLabel) fLabel.innerText = totalFish.toLocaleString();
        }

        // FCR is calculated via calculateFCR() injected later...

    } catch (e) {
        console.error("Aqua initialization error: ", e);
    }
}

async function refreshAquaDashboard() {
    if (!window.insforge) return;
    try {
        // 1. Fetch total active biomass from growth samplings
        const slist = await window.insforge.fetch('aqua_growth_sampling', '?select=pond_id,est_total_biomass_kg,sampling_date');
        let totalBiomass = 0;
        if (slist && !slist.error) {
            // Keep only latest sampling per pond
            const latestS = {};
            slist.forEach(s => {
                if (!latestS[s.pond_id] || new Date(s.sampling_date) > new Date(latestS[s.pond_id].sampling_date)) {
                    latestS[s.pond_id] = s;
                }
            });
            Object.values(latestS).forEach(s => totalBiomass += parseFloat(s.est_total_biomass_kg || 0));
        }
        const bLabel = document.getElementById('kpi-aq-biomass');
        if (bLabel) bLabel.innerText = totalBiomass.toLocaleString() + " Kg";

        // 2. Load Pond Status Table
        const ponds = await window.insforge.fetch('aqua_ponds', '?select=id,name,max_capacity,status');
        const water = await window.insforge.fetch('aqua_daily_water_quality', '?select=pond_id,do_mg_l,ph_level,ammonia_mg_l,test_time');

        let tbody = document.getElementById('aq-dashboard-ponds-tbody');
        if (!tbody) return;

        if (!ponds || ponds.error || ponds.length === 0) {
            tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;">No pond data found.</td></tr>';
            return;
        }

        let html = '';
        let alerts = [];

        ponds.forEach(p => {
            // find latest water reading for this pond
            let latestW = null;
            if (water && !water.error) {
                const pWater = water.filter(w => w.pond_id === p.id);
                if (pWater.length > 0) {
                    pWater.sort((a, b) => new Date(b.test_time) - new Date(a.test_time));
                    latestW = pWater[0];
                }
            }

            let doVal = latestW ? latestW.do_mg_l : '-';
            let phVal = latestW ? latestW.ph_level : '-';
            let nh3Val = latestW ? (latestW.ammonia_mg_l || '0.01') : '-';

            let statusHtml = '<span class="pill pill-green">🟢 Healthy</span>';

            // Critical checks
            if (latestW) {
                if (parseFloat(latestW.do_mg_l) < 3.0) {
                    statusHtml = '<span class="pill pill-red">🔴 CRITICAL DO</span>';
                    alerts.push(`🔴 URGENT: Dissolved Oxygen low in ${p.name} (${latestW.do_mg_l} mg/L). Turn on emergency aerators!`);
                } else if (parseFloat(latestW.ph_level) < 6.0 || parseFloat(latestW.ph_level) > 9.0) {
                    statusHtml = '<span class="pill pill-orange">🟠 pH Alert</span>';
                    alerts.push(`🟠 WARNING: pH out of range in ${p.name} (${latestW.ph_level}). Check lime dosage.`);
                } else if (parseFloat(latestW.ammonia_mg_l) > 0.1) {
                    statusHtml = '<span class="pill pill-red">🔴 Toxic NH3</span>';
                    alerts.push(`🔴 TOXIC: Ammonia spike in ${p.name} (${latestW.ammonia_mg_l} mg/L). Flush water immediately.`);
                }
            } else {
                statusHtml = '<span class="pill pill-gray">⚪ No Data</span>';
            }

            html += `<tr>
                <td><strong>${escapeHtml(p.name)}</strong></td>
                <td>Mixed Polyculture</td>
                <td>${escapeHtml(doVal)}</td>
                <td>${escapeHtml(phVal)}</td>
                <td>${escapeHtml(nh3Val)}</td>
                <td>${statusHtml}</td>
                <td><button type="button"  class="ent-btn" onclick="showAqTab('aq-water')">Log & View</button></td>
            </tr>`;
        });

        tbody.innerHTML = html;

        // Render Alerts
        const alertDiv = document.getElementById('aq-dashboard-alerts');
        if (alertDiv) {
            if (alerts.length > 0) {
                let aHtml = '';
                alerts.forEach(a => {
                    aHtml += `<div style="padding:10px; border-left:4px solid var(--accent-red); background:rgba(255,50,50,0.1); margin-bottom:10px;">${a}</div>`;
                });
                alertDiv.innerHTML = aHtml;
            } else {
                alertDiv.innerHTML = '<div style="color:var(--text-2);">✅ All parameters operational. No critical alerts today.</div>';
            }
        }

    } catch (e) {
        console.error("Dashboard refresh error:", e);
    }
}

