async function loadAquaPonds() {
    if (!window.insforge) return;
    try {
        const ponds = await window.insforge.fetch('aqua_ponds', '?select=*');
        const tbody = document.getElementById('aq-ponds-tbody');
        if (!tbody) return;

        if (!ponds || ponds.error || ponds.length === 0) {
            tbody.innerHTML = '<tr><td colspan="6" style="text-align:center;">No pond infrastructure found.</td></tr>';
            return;
        }

        // Also populate the dropdown in water quality modal
        const wqSelect = document.getElementById('aq-wq-pond');
        if (wqSelect) wqSelect.innerHTML = '';

        let html = '';
        ponds.forEach(p => {
            html += `<tr>
                <td><strong>${escapeHtml(p.name)}</strong></td>
                <td>${escapeHtml(p.type || 'Earthen Pond')}</td>
                <td>${escapeHtml(p.area_sqm || '-')}</td>
                <td>${escapeHtml(p.volume_cum || '-')}</td>
                <td>${escapeHtml(p.aeration_info || 'Natural')}</td>
                <td><span class="pill pill-green">${escapeHtml(p.status || 'Active')}</span></td>
            </tr>`;

            if (wqSelect) {
                wqSelect.innerHTML += `<option value="${escapeHtml(p.id)}">${escapeHtml(p.name)}</option>`;
            }
        });
        tbody.innerHTML = html;
    } catch (e) { console.error(e); }
}

async function loadAquaStocking() {
    if (!window.insforge) return;
    try {
        const cycles = await window.insforge.fetch('aqua_culture_cycles', '?select=*,aqua_ponds(name)');
        const stocking = await window.insforge.fetch('aqua_stocking_records', '?select=*,aqua_species(name)');

        const tbody = document.getElementById('aq-stocking-tbody');
        if (!tbody) return;

        if (!cycles || cycles.error || cycles.length === 0) {
            tbody.innerHTML = '<tr><td colspan="6" style="text-align:center;">No active culture cycles found.</td></tr>';
            return;
        }

        let html = '';
        cycles.forEach(c => {
            let sRecords = stocking ? stocking.filter(s => s.cycle_id === c.id) : [];
            let speciesNames = sRecords.map(s => s.aqua_species ? s.aqua_species.name : 'Unknown').join(', ');
            let totalSeed = sRecords.reduce((sum, s) => sum + (parseInt(s.stock_count) || 0), 0);
            let avgW = sRecords.length > 0 ? (sRecords.reduce((sum, s) => sum + parseFloat(s.avg_weight_g || 0), 0) / sRecords.length).toFixed(1) : '-';

            let pondName = c.aqua_ponds ? c.aqua_ponds.name : 'Unknown Pond';

            html += `<tr>
                <td><strong>${escapeHtml(c.cycle_name || 'Cycle')}</strong></td>
                <td>${escapeHtml(pondName)}</td>
                <td>${escapeHtml(speciesNames || 'Mixed')}</td>
                <td>${totalSeed.toLocaleString()}</td>
                <td>${avgW}g</td>
                <td>${escapeHtml(c.expected_harvest_date || 'TBD')}</td>
            </tr>`;
        });
        tbody.innerHTML = html;
    } catch (e) { console.error(e); }
}

async function loadAquaWaterLogs() {
    if (!window.insforge) return;
    try {
        const water = await window.insforge.fetch('aqua_daily_water_quality', '?select=*,aqua_ponds(name)&order=test_time.desc&limit=50');
        const tbody = document.getElementById('aq-water-tbody');
        if (!tbody) return;

        if (!water || water.error || water.length === 0) {
            tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;">No water quality logs found.</td></tr>';
            return;
        }

        let html = '';
        water.forEach(w => {
            let pondName = w.aqua_ponds ? w.aqua_ponds.name : 'Unknown';
            let doVal = parseFloat(w.do_mg_l || 0);
            let doPill = doVal < 3.0 ? `<span class="pill pill-red">${doVal}</span>` : `<span class="pill pill-green">${doVal}</span>`;
            let phVal = parseFloat(w.ph_level || 0);
            let phPill = (phVal < 6.5 || phVal > 8.5) ? `<span class="pill pill-orange">${phVal}</span>` : `<span class="pill pill-green">${phVal}</span>`;
            let nhVal = parseFloat(w.ammonia_mg_l || 0);
            let nhPill = nhVal > 0.1 ? `<span class="pill pill-red">${nhVal}</span>` : `<span class="pill pill-green">${nhVal}</span>`;

            let overallStatus = (doVal < 3.0 || nhVal > 0.1 || phVal < 6.0 || phVal > 9.0) ? '🔴 Critical' : '🟢 Healthy';

            let d = new Date(w.test_time).toLocaleString();

            html += `<tr>
                <td>${escapeHtml(d)}</td>
                <td><strong>${escapeHtml(pondName)}</strong></td>
                <td>${escapeHtml(w.temperature_c || '-')}</td>
                <td>${phPill}</td>
                <td>${doPill}</td>
                <td>${nhPill}</td>
                <td>${escapeHtml(overallStatus)}</td>
            </tr>`;
        });
        tbody.innerHTML = html;
    } catch (e) { console.error(e); }
}

async function saveAquaWaterQuality() {
    if (!window.insforge) return alert("InsForge Database not connected.");

    const pondId = document.getElementById('aq-wq-pond').value;
    const temp = document.getElementById('aq-wq-temp').value;
    const ph = document.getElementById('aq-wq-ph').value;
    const doo = document.getElementById('aq-wq-do').value;
    const nh3 = document.getElementById('aq-wq-nh3').value;

    if (!pondId || !ph || !doo) {
        return alert("Pond, pH, and DO are mandatory fields!");
    }

    try {
        const payload = {
            pond_id: pondId,
            temperature_c: parseFloat(temp) || null,
            ph_level: parseFloat(ph),
            do_mg_l: parseFloat(doo),
            ammonia_mg_l: parseFloat(nh3) || 0,
            tested_by: 'Farm Supervisor'
        };

        const res = await window.insforge.insert('aqua_daily_water_quality', [payload]);
        if (!res.error) {
            document.getElementById('aq-water-modal').style.display = 'none';
            // Clear inputs
            document.getElementById('aq-wq-temp').value = '';
            document.getElementById('aq-wq-ph').value = '';
            document.getElementById('aq-wq-do').value = '';
            document.getElementById('aq-wq-nh3').value = '';

            // Refresh tables
            loadAquaWaterLogs();
            loadAquaPhaseThree();
            loadAquaPhaseFour();


            refreshAquaDashboard();
        } else {
            console.error(res);
            alert("Database Error: " + JSON.stringify(res.error));
        }
    } catch (e) {
        console.error(e);
        alert("Exception saving water quality.");
    }
}

