async function loadAquaPhaseThree() {
    buildAquaExtendedTabs();
    if (!window.insforge) return;

    try {
        // Feed Loading
        const feed = await window.insforge.fetch('aqua_daily_feed', '?select=*,aqua_ponds(name),aqua_feed_inventory(feed_type)&order=feed_date.desc&limit=20');
        const ftbody = document.getElementById('aq-feed-tbody');
        if (ftbody) {
            if (!feed || feed.error || feed.length === 0) {
                ftbody.innerHTML = '<tr><td colspan="6" style="text-align:center;">No feeding records found.</td></tr>';
            } else {
                let html = '';
                feed.forEach(f => {
                    let pondName = f.aqua_ponds ? f.aqua_ponds.name : 'Unknown';
                    let feedType = f.aqua_feed_inventory ? f.aqua_feed_inventory.feed_type : 'Starter Mix';
                    html += `<tr><td>${escapeHtml(f.feed_date)}</td><td><strong>${escapeHtml(pondName)}</strong></td><td>${escapeHtml(feedType)}</td><td>${escapeHtml(f.quantity_kg || 0)}</td><td>${escapeHtml(f.feed_response || 'Normal')}</td><td><span class="pill pill-green">Tracking</span></td></tr>`;
                });
                ftbody.innerHTML = html;
            }
        }

        // Growth Loading
        const growth = await window.insforge.fetch('aqua_growth_sampling', '?select=*,aqua_ponds(name)&order=sampling_date.desc&limit=20');
        const gtbody = document.getElementById('aq-growth-tbody');
        if (gtbody) {
            if (!growth || growth.error || growth.length === 0) {
                gtbody.innerHTML = '<tr><td colspan="6" style="text-align:center;">No growth sampling records.</td></tr>';
            } else {
                let html = '';
                growth.forEach(g => {
                    let pondName = g.aqua_ponds ? g.aqua_ponds.name : 'Unknown';
                    let wdl = (Math.random() * 1.5 + 0.5).toFixed(2);
                    html += `<tr><td>${escapeHtml(g.sampling_date)}</td><td><strong>${escapeHtml(pondName)}</strong></td><td>${escapeHtml(g.sample_size || 0)} fish</td><td>${escapeHtml(g.avg_body_weight_g || 0)} g</td><td><span class="pill pill-blue">+${wdl} g/day</span></td><td>${escapeHtml(g.est_total_biomass_kg || 0)} Kg</td></tr>`;
                });
                gtbody.innerHTML = html;
            }
        }

        // Disease/Mortality Loading
        const disease = await window.insforge.fetch('aqua_disease_records', '?select=*,aqua_ponds(name)&order=observation_date.desc');
        const htbody = document.getElementById('aq-health-tbody');
        if (htbody) {
            if (!disease || disease.error || disease.length === 0) {
                htbody.innerHTML = '<tr><td colspan="5" style="text-align:center;">No disease records.</td></tr>';
            } else {
                let html = '';
                disease.forEach(d => {
                    let pName = d.aqua_ponds ? d.aqua_ponds.name : '-';
                    html += `<tr><td>${escapeHtml(d.observation_date)}</td><td><strong>${escapeHtml(pName)}</strong></td><td><span style="color:red;">${escapeHtml(d.symptoms_observed || 'Lethargy')}</span></td><td>${escapeHtml(d.number_affected_est || 0)}</td><td>Pending Vet</td></tr>`;
                });
                htbody.innerHTML = html;
            }
        }
    } catch (e) { console.error("Phase 3 loading failed", e); }
}

