async function loadAquaPhaseFour() {
    buildAquaFinalTabs();
    if (!window.insforge) return;
    try {
        // Shrimp 
        const ct = await window.insforge.fetch('aqua_check_tray_monitoring', '?select=*,aqua_ponds(name)&order=check_date.desc&limit=20');
        const stbody = document.getElementById('aq-shrimp-tbody');
        if (stbody) {
            if (!ct || ct.error || ct.length === 0) {
                stbody.innerHTML = '<tr><td colspan="5" style="text-align:center;">No check tray records.</td></tr>';
            } else {
                let html = '';
                ct.forEach(c => {
                    let pName = c.aqua_ponds ? c.aqua_ponds.name : '-';
                    html += `<tr><td>${escapeHtml(c.check_date)}</td><td><strong>${escapeHtml(pName)}</strong></td><td>${escapeHtml(c.feed_in_tray_g || 0)}</td><td>${escapeHtml(c.gut_fullness || 'Full')}</td><td>${escapeHtml(c.action_taken || 'None')}</td></tr>`;
                });
                stbody.innerHTML = html;
            }
        }
    } catch (e) { console.error("Phase 4 loading failed", e); }
}


