function gridTab(id, btn) {
    document.querySelectorAll('#page-container .vet-pane[id^="grid-"]').forEach(p => p.classList.remove('active'));
    document.querySelectorAll('#page-container .vet-tab-btn').forEach(b => b.classList.remove('active'));
    const el = document.getElementById('grid-' + id);
    if (el) el.classList.add('active');
    if (btn) btn.classList.add('active');
}
function windTab(id, btn) {
    var container = document.getElementById('page-container') || document.body;
    container.querySelectorAll('.dairy-pane').forEach(function (e) { e.classList.remove('active'); });
    container.querySelectorAll('.dairy-tab-btn').forEach(function (e) { e.classList.remove('active'); });
    const target = document.getElementById('wnd-' + id);
    if (target) target.classList.add('active');
    if (btn) btn.classList.add('active');
}


window.windSubTab = function (subId, btn, paneId) {
    const nav = btn.closest('.vet-nav');
    if (nav) {
        nav.querySelectorAll('.vet-tab-btn').forEach(b => b.classList.remove('active'));
        btn.classList.add('active');
    }
    const parentPane = document.getElementById(paneId);
    if (parentPane) {
        parentPane.querySelectorAll('.wind-sub-pane').forEach(p => p.style.display = 'none');
        const targetPane = parentPane.querySelector('#st-' + subId);
        if (targetPane) targetPane.style.display = 'block';
    }
};

