function _setStatus(id, msg, ok) {
    var el = document.getElementById(id);
    if (el) { el.textContent = ok ? '✓ ' + msg : '✗ ' + msg; el.className = 'form-status ' + (ok ? 'ok' : 'err'); }
}
function _getVal(id) { var el = document.getElementById(id); return el ? el.value : ''; }
function _today() { return new Date().toISOString().split('T')[0]; }

/* ── SOLAR ────────────────────────────────────────────────── */
async function saveSolarReading() {
    var data = {
        reading_date: _getVal('sol-date') || _today(),
        array_id: _getVal('sol-array'),
        kwh_generated: parseFloat(_getVal('sol-kwh')) || 0,
        irradiance: parseFloat(_getVal('sol-irr')) || 0,
        module_temp: parseFloat(_getVal('sol-temp')) || 0,
        performance_ratio: parseFloat(_getVal('sol-pr')) || 0,
        cleaning_done: _getVal('sol-cleaning'),
        notes: _getVal('sol-notes')
    };
    if (!data.array_id) { _setStatus('sol-status', 'Select an array', false); return; }
    var ok = await window.insforge.insert('solar_readings', data);
    _setStatus('sol-status', ok ? 'Saved!' : 'Save failed', !!ok);
    if (ok) loadSolarRecent();
}
async function loadSolarRecent() {
    try {
        var rows = await window.insforge.query('SELECT reading_date,array_id,kwh_generated,irradiance,performance_ratio FROM solar_readings ORDER BY reading_date DESC LIMIT 10');
        var tbl = document.getElementById('sol-recent-tbl');
        if (!tbl || !rows) return;
        tbl.innerHTML = '<tr><th>Date</th><th>Array</th><th>kWh</th><th>Irr.</th><th>PR%</th></tr>' +
            (rows.map(r => '<tr><td>' + r.reading_date + '</td><td>' + r.array_id + '</td><td>' + (r.kwh_generated || 0).toLocaleString() + '</td><td>' + r.irradiance + '</td><td>' + r.performance_ratio + '%</td></tr>').join('') || '<tr><td colspan="5" style="text-align:center">No records yet</td></tr>');
    } catch (e) { console.error('Operation failed:', e); }
}

