/* ── Live calc wiring for Poultry forms ── */
function _wireLive() {
    // Egg HDP auto-calc
    ['egg-total', 'egg-broken', 'egg-birds', 'egg-rate'].forEach(function (id) {
        var el = document.getElementById(id);
        if (el) el.addEventListener('input', function () {
            var total = parseInt(_getVal('egg-total')) || 0;
            var broken = parseInt(_getVal('egg-broken')) || 0;
            var birds = parseInt(_getVal('egg-birds')) || 1;
            var rate = parseFloat(_getVal('egg-rate')) || 0;
            var net = total - broken;
            var hdp = birds > 0 ? ((total / birds) * 100).toFixed(1) : 0;
            var rev = (net * rate).toFixed(0);
            var hdpEl = document.getElementById('egg-hdp-calc');
            var netEl = document.getElementById('egg-net-calc');
            var revEl = document.getElementById('egg-rev-calc');
            if (hdpEl) hdpEl.textContent = hdp + '%';
            if (netEl) netEl.textContent = net.toLocaleString();
            if (revEl) revEl.textContent = '₹' + parseInt(rev).toLocaleString();
        });
    });
    // Broiler revenue auto-calc
    ['brs-weight', 'brs-rate', 'brs-birds'].forEach(function (id) {
        var el = document.getElementById(id);
        if (el) el.addEventListener('input', function () {
            var w = parseFloat(_getVal('brs-weight')) || 0;
            var r = parseFloat(_getVal('brs-rate')) || 0;
            var b = parseInt(_getVal('brs-birds')) || 1;
            var revEl = document.getElementById('brs-rev');
            var avgEl = document.getElementById('brs-avg');
            if (revEl) revEl.textContent = '₹' + (w * r).toLocaleString();
            if (avgEl) avgEl.textContent = b > 0 ? (w / b).toFixed(2) + ' kg' : '0 kg';
        });
    });
    // BW vs target
    ['bw-avg', 'bw-target'].forEach(function (id) {
        var el = document.getElementById(id);
        if (el) el.addEventListener('input', function () {
            var avg = parseFloat(_getVal('bw-avg')) || 0;
            var tgt = parseFloat(_getVal('bw-target')) || 0;
            var el2 = document.getElementById('bw-vs-target');
            if (el2 && tgt > 0) {
                var diff = ((avg - tgt) / tgt * 100).toFixed(1);
                el2.textContent = (diff >= 0 ? '+' : '') + diff + '% vs target';
                el2.style.color = diff >= 0 ? '#00e676' : '#ff5252';
            }
        });
    });
    // Aqua feed rate
    ['aqf-qty', 'aqf-biomass', 'aqf-cost', 'aqf-times'].forEach(function (id) {
        var el = document.getElementById(id);
        if (el) el.addEventListener('input', function () {
            var qty = parseFloat(_getVal('aqf-qty')) || 0;
            var bio = parseFloat(_getVal('aqf-biomass')) || 1;
            var cost = parseFloat(_getVal('aqf-cost')) || 0;
            var frEl = document.getElementById('aqf-feedrate');
            var fcEl = document.getElementById('aqf-cost-today');
            if (frEl) frEl.textContent = bio > 0 ? ((qty / bio) * 100).toFixed(2) + '%' : '—';
            if (fcEl) fcEl.textContent = '₹' + (qty * cost).toLocaleString();
        });
    });
    // Aqua harvest revenue
    ['aqh-weight', 'aqh-rate'].forEach(function (id) {
        var el = document.getElementById(id);
        if (el) el.addEventListener('input', function () {
            var w = parseFloat(_getVal('aqh-weight')) || 0;
            var r = parseFloat(_getVal('aqh-rate')) || 0;
            var el2 = document.getElementById('aqh-rev');
            if (el2) el2.textContent = '₹' + (w * r).toLocaleString();
        });
    });
    // Aqua water quality warnings
    ['aqw-do', 'aqw-ph', 'aqw-ammonia'].forEach(function (id) {
        var el = document.getElementById(id);
        if (el) el.addEventListener('input', function () {
            var alerts = [];
            var doVal = parseFloat(_getVal('aqw-do')) || 0;
            var ph = parseFloat(_getVal('aqw-ph')) || 0;
            var nh3 = parseFloat(_getVal('aqw-ammonia')) || 0;
            if (doVal > 0 && doVal < 4) alerts.push('⚠️ DO Critical (<4 mg/L)');
            if (ph > 0 && (ph < 6.5 || ph > 9)) alerts.push('⚠️ pH out of range (6.5-9)');
            if (nh3 > 0.1) alerts.push('⚠️ Ammonia high (>0.1 mg/L)');
            var alertEl = document.getElementById('aqw-alerts');
            if (alertEl) alertEl.innerHTML = alerts.map(function (a) {
                return '<span style="color:#ff5252;font-weight:700;margin-right:12px">' + a + '</span>';
            }).join('');
        });
    });
}
// Wire live calculations on page load and on tab change
document.addEventListener('DOMContentLoaded', function () { _wireLive(); });
setTimeout(_wireLive, 2000);

/* ── POULTRY — Egg Collection ── */

async function loadEggRecent() {
    try {
        var rows = await window.insforge.query('SELECT collection_date,batch_id,shed_id,total_eggs,broken_eggs,hdp_pct FROM poultry_egg_collection ORDER BY collection_date DESC LIMIT 10');
        var tbl = document.getElementById('egg-recent-tbl');
        if (!tbl || !rows) return;
        tbl.innerHTML = '<tr><th>Date</th><th>Batch</th><th>Shed</th><th>Total</th><th>Broken</th><th>HDP%</th></tr>' +
            (rows.map(function (r) { return '<tr><td>' + r.collection_date + '</td><td>' + r.batch_id + '</td><td>' + r.shed_id + '</td><td>' + r.total_eggs + '</td><td>' + r.broken_eggs + '</td><td><span class="pill ' + (r.hdp_pct >= 70 ? 'pill-green' : r.hdp_pct >= 55 ? 'pill-amber' : 'pill-red') + '">' + r.hdp_pct + '%</span></td></tr>'; }).join('') ||
                '<tr><td colspan="6" style="text-align:center">No records</td></tr>');
    } catch (e) { console.error('Operation failed:', e); }
}

/* ── POULTRY — Mortality ── */
async function saveMortality() {
    var data = {
        mort_date: _getVal('mort-date') || _today(),
        batch_id: _getVal('mort-batch'),
        shed_id: _getVal('mort-shed'),
        count: parseInt(_getVal('mort-count')) || 0,
        cause: _getVal('mort-cause'),
        disposal: _getVal('mort-disposal'),
        notes: _getVal('mort-notes')
    };
    if (!data.batch_id) { _setStatus('mort-status', 'Select a batch', false); return; }
    var ok = await window.insforge.insert('poultry_mortality', data);
    _setStatus('mort-status', ok ? 'Recorded!' : 'Save failed', !!ok);
    if (ok) {
        loadMortRecent();
        // Auto-expense: culled birds cost
        await window.insforge.insert('finance_entries', {
            entry_date: data.mort_date,
            type: 'Expense', category: 'Poultry Mortality Loss', module: 'Poultry',
            amount: 0, notes: 'Auto: ' + data.count + ' deaths in ' + data.batch_id + ' — ' + data.cause
        });
    }
}

async function loadMortRecent() {
    try {
        var rows = await window.insforge.query('SELECT mort_date,batch_id,shed_id,count,cause FROM poultry_mortality ORDER BY mort_date DESC LIMIT 10');
        var tbl = document.getElementById('mort-recent-tbl');
        if (!tbl || !rows) return;
        tbl.innerHTML = '<tr><th>Date</th><th>Batch</th><th>Shed</th><th>Count</th><th>Cause</th></tr>' +
            (rows.map(function (r) { return '<tr><td>' + r.mort_date + '</td><td>' + r.batch_id + '</td><td>' + r.shed_id + '</td><td><span class="pill pill-red">' + r.count + '</span></td><td>' + r.cause + '</td></tr>'; }).join('') ||
                '<tr><td colspan="5" style="text-align:center">No records</td></tr>');
    } catch (e) { console.error('Operation failed:', e); }
}

