/* ── POULTRY — Body Weight ── */
async function saveBodyWeight() {
    var avg = parseFloat(_getVal('bw-avg')) || 0;
    var tgt = parseFloat(_getVal('bw-target')) || 0;
    var data = {
        bw_date: _getVal('bw-date') || _today(),
        batch_id: _getVal('bw-batch'),
        age_days: parseInt(_getVal('bw-age')) || 0,
        sample_count: parseInt(_getVal('bw-sample')) || 0,
        avg_bw_g: avg,
        target_bw_g: tgt,
        deviation_pct: tgt > 0 ? parseFloat(((avg - tgt) / tgt * 100).toFixed(2)) : 0,
        cv_pct: parseFloat(_getVal('bw-cv')) || 0,
        notes: _getVal('bw-notes')
    };
    var ok = await window.insforge.insert('poultry_body_weight', data);
    _setStatus('bw-status', ok ? 'Saved!' : 'Save failed', !!ok);
    if (ok) {
        var tbl = document.getElementById('bw-tbl');
        if (tbl) {
            var row = '<tr><td>' + data.bw_date + '</td><td>' + data.batch_id + '</td><td>' + data.age_days + '</td><td>' + data.avg_bw_g + '</td><td>' + data.target_bw_g + '</td><td>' + data.cv_pct + '%</td></tr>';
            tbl.innerHTML = tbl.innerHTML.replace('<tr><td colspan="6"', row + '<tr style="display:none"><td colspan="6"');
        }
    }
}

