async function loadAquaWaterTbl() {
    try {
        var rows = await window.insforge.query('SELECT reading_date,pond_id,session,dissolved_o2,ph,water_temp,ammonia FROM aqua_daily_water ORDER BY reading_date DESC, session DESC LIMIT 14');
        var tbl = document.getElementById('aqw-tbl');
        if (!tbl || !rows) return;
        tbl.innerHTML = '<tr><th>Date</th><th>Pond</th><th>Sess</th><th>DO</th><th>pH</th><th>Temp</th><th>NH₃</th></tr>' +
            (rows.map(function (r) {
                return '<tr><td>' + r.reading_date + '</td><td>' + r.pond_id + '</td><td>' + r.session + '</td><td><span class="pill ' + (r.dissolved_o2 >= 4 ? 'pill-green' : 'pill-red') + '">' + r.dissolved_o2 + '</span></td><td>' + r.ph + '</td><td>' + r.water_temp + '°C</td><td>' + (r.ammonia > 0.1 ? '<span class="pill pill-red">' + r.ammonia + '</span>' : r.ammonia) + '</td></tr>';
            }).join('') || '<tr><td colspan="7" style="text-align:center">No records</td></tr>');
    } catch (e) { console.error('Operation failed:', e); }
}

