/* ============================================================
   PHASE 2C — DAIRY, VET TREATMENT, CRM, STAFF
   ============================================================ */

/* ── Live calc wiring Phase 2C ── */
(function () {
    function wire(ids, fn) {
        ids.forEach(function (id) {
            var el = document.getElementById(id);
            if (el) el.addEventListener('input', fn);
        });
    }
    // Milk revenue calc
    wire(['mlk-vol', 'mlk-rate', 'mlk-fat', 'mlk-snf'], function () {
        var v = parseFloat(_getVal('mlk-vol')) || 0, r = parseFloat(_getVal('mlk-rate')) || 0;
        var fat = parseFloat(_getVal('mlk-fat')) || 0, snf = parseFloat(_getVal('mlk-snf')) || 0;
        var revEl = document.getElementById('mlk-rev-calc');
        var tsEl = document.getElementById('mlk-ts-calc');
        if (revEl) revEl.textContent = '₹' + (v * r).toFixed(2);
        if (tsEl && fat && snf) tsEl.textContent = (fat + snf).toFixed(2) + '% TS';
    });
    // Feed cost calc
    wire(['dfd-qty', 'dfd-cost'], function () {
        var q = parseFloat(_getVal('dfd-qty')) || 0, c = parseFloat(_getVal('dfd-cost')) || 0;
        var el = document.getElementById('dfd-cost-calc');
        if (el) el.textContent = '₹' + (q * c).toLocaleString();
    });
    // Delivery invoice value
    wire(['dlv-qty', 'dlv-rate'], function () {
        var q = parseFloat(_getVal('dlv-qty')) || 0, r = parseFloat(_getVal('dlv-rate')) || 0;
        var el = document.getElementById('dlv-val');
        if (el) el.textContent = '₹' + (q * r).toLocaleString();
    });
    setTimeout(function () {
        wire(['mlk-vol', 'mlk-rate', 'mlk-fat', 'mlk-snf'], function () { });
        wire(['dfd-qty', 'dfd-cost'], function () { });
        wire(['dlv-qty', 'dlv-rate'], function () { });
    }, 1500);
})();

/* ── SMART DAIRY — Milk Entry ── */
async function saveMilkEntry() {
    var vol = parseFloat(_getVal('mlk-vol')) || 0;
    var rate = parseFloat(_getVal('mlk-rate')) || 0;
    var data = {
        collection_date: _getVal('mlk-date') || _today(),
        cow_id: _getVal('mlk-cow'),
        shed: _getVal('mlk-shed'),
        session: _getVal('mlk-session'),
        volume_l: vol,
        fat_pct: parseFloat(_getVal('mlk-fat')) || 0,
        snf_pct: parseFloat(_getVal('mlk-snf')) || 0,
        milk_temp: parseFloat(_getVal('mlk-temp')) || 0,
        rate_per_l: rate,
        revenue: parseFloat((vol * rate).toFixed(2))
    };
    if (!data.cow_id) { _setStatus('mlk-status', 'Enter Cow ID', false); return; }
    var ok = await window.insforge.insert('dairy_milk_records', data);
    _setStatus('mlk-status', ok ? 'Saved! ₹' + data.revenue : 'Save failed', !!ok);
    if (ok) {
        loadMilkTable();
        if (data.revenue > 0) {
            await window.insforge.insert('finance_entries', {
                entry_date: data.collection_date,
                type: 'Revenue', category: 'Milk Sales', module: 'Dairy',
                amount: data.revenue,
                notes: 'Auto: ' + data.cow_id + ' ' + data.session + ' ' + vol + 'L @ ₹' + rate
            });
        }
    }
}
async function loadMilkTable() {
    try {
        var rows = await window.insforge.query('SELECT collection_date,cow_id,session,volume_l,fat_pct,snf_pct,revenue FROM dairy_milk_records ORDER BY collection_date DESC LIMIT 10');
        var tbl = document.getElementById('mlk-tbl');
        if (!tbl || !rows) return;
        tbl.innerHTML = '<tr><th>Date</th><th>Cow ID</th><th>Sess</th><th>Vol(L)</th><th>Fat%</th><th>SNF%</th><th>Revenue</th></tr>' +
            (rows.map(function (r) { return '<tr><td>' + r.collection_date + '</td><td style="font-family:monospace">' + r.cow_id + '</td><td>' + r.session + '</td><td>' + r.volume_l + '</td><td>' + r.fat_pct + '</td><td>' + r.snf_pct + '</td><td style="color:#00e676">₹' + r.revenue + '</td></tr>'; }).join('') ||
                '<tr><td colspan="7" style="text-align:center">No records</td></tr>');
    } catch (e) { console.error('Operation failed:', e); }
}

