/* ── Live calcs ── */
(function () {
    function wire(ids, fn) {
        setTimeout(function () {
            ids.forEach(function (id) {
                var el = document.getElementById(id);
                if (el) el.addEventListener('input', fn);
            });
        }, 500);
    }
    wire(['h2-produced', 'h2-power', 'h2-dispatched', 'h2-rate'], function () {
        var prod = parseFloat(_getVal('h2-produced')) || 0;
        var power = parseFloat(_getVal('h2-power')) || 0;
        var disp = parseFloat(_getVal('h2-dispatched')) || 0;
        var rate = parseFloat(_getVal('h2-rate')) || 0;
        var effEl = document.getElementById('h2-eff-calc');
        var revEl = document.getElementById('h2-rev-calc');
        if (effEl && power > 0) effEl.textContent = (prod / power).toFixed(2) + ' kg/MWh';
        if (revEl) revEl.textContent = '₹' + (disp * rate).toLocaleString();
    });
    wire(['grd-grid-export', 'grd-export-rate', 'grd-solar-gen', 'grd-wind-gen', 'grd-demand-avg'], function () {
        var exp = parseFloat(_getVal('grd-grid-export')) || 0;
        var rate = parseFloat(_getVal('grd-export-rate')) || 0;
        var sol = parseFloat(_getVal('grd-solar-gen')) || 0;
        var wnd = parseFloat(_getVal('grd-wind-gen')) || 0;
        var dem = parseFloat(_getVal('grd-demand-avg')) || 1;
        var revEl = document.getElementById('grd-rev-calc');
        var sufEl = document.getElementById('grd-suf-calc');
        if (revEl) revEl.textContent = '₹' + (exp * rate * 1000).toLocaleString();
        if (sufEl && dem > 0) sufEl.textContent = Math.min(100, ((sol + wnd) / dem * 100)).toFixed(1) + '%';
    });
    wire(['trh-qty', 'trh-rate'], function () {
        var q = parseFloat(_getVal('trh-qty')) || 0;
        var r = parseFloat(_getVal('trh-rate')) || 0;
        var el = document.getElementById('trh-rev-calc');
        if (el) el.textContent = '₹' + (q * r).toLocaleString();
    });
})();

