/* PHASE-3-ANALYTICS */




/* ============================================================
   PHASE 4 — SMART ALERT ENGINE
   Rules-based threshold monitoring across all modules.
   Fires visual + DB alerts whenever thresholds are breached.
   ============================================================
   PHASE-4-ALERTS */

/* ── Alert Panel State ── */
window._alerts = window._alerts || [];
window._alertCount = 0;

/* ── Severity config ── */
var _SEVERITY = {
    CRITICAL: { color: '#ef4444', bg: 'rgba(239,68,68,0.12)', icon: '🚨', sound: true },
    WARNING: { color: '#f59e0b', bg: 'rgba(245,158,11,0.10)', icon: '⚠️', sound: false },
    INFO: { color: '#10b981', bg: 'rgba(16,185,129,0.08)', icon: 'ℹ️', sound: false }
};

/* ── Post alert to UI + DB ── */
async function _fireAlert(module, severity, title, message, metricVal, threshold) {
    var cfg = _SEVERITY[severity] || _SEVERITY.INFO;

    // Avoid duplicate alerts within 30 min for same title
    var now = Date.now();
    var key = module + ':' + title;
    if (window._alertDedup && window._alertDedup[key] && (now - window._alertDedup[key]) < 1800000) return;
    if (!window._alertDedup) window._alertDedup = {};
    window._alertDedup[key] = now;

    var alertObj = {
        module: module, severity: severity, title: title, message: message,
        metricVal: metricVal, threshold: threshold, time: new Date().toLocaleTimeString('en-IN'), id: now
    };
    window._alerts.unshift(alertObj);
    window._alertCount++;
    _updateAlertBadge();
    _injectAlertCard(alertObj, cfg);

    // Save to DB
    try {
        if (window.insforge) {
            await window.insforge.insert('farm_alerts', {
                module: module, severity: severity, title: title, message: message,
                metric_value: metricVal, threshold: threshold
            });
        }
    } catch (e) { /* non-blocking */ }

    // OS notification (if permitted)
    if (cfg.sound && Notification && Notification.permission === 'granted') {
        new Notification('Vedavathi ' + severity, { body: title + ' — ' + message, icon: '🌿' });
    }
}

/* ── Bell badge updater ── */
function _updateAlertBadge() {
    var badge = document.getElementById('alert-count-badge');
    if (!badge) return;
    badge.textContent = window._alertCount > 99 ? '99+' : window._alertCount;
    badge.style.display = window._alertCount > 0 ? 'block' : 'none';
}

/* ── Inject into alert panel ── */
function _injectAlertCard(a, cfg) {
    var panel = document.getElementById('alert-slide-panel');
    if (!panel) return;
    var card = document.createElement('div');
    card.className = 'alert-card-item';
    card.setAttribute('data-alert-id', a.id);
    card.style.cssText = 'padding:10px 14px;border-left:3px solid ' + cfg.color + ';background:' + cfg.bg + ';margin-bottom:6px;border-radius:0 8px 8px 0;cursor:pointer;';
    card.innerHTML = '<div style="display:flex;justify-content:space-between;align-items:center;"><span style="font-weight:700;color:' + cfg.color + ';font-size:0.78rem">' + cfg.icon + ' ' + a.severity + '</span><span style="font-size:0.68rem;color:var(--text-3)">' + a.time + '</span></div>'
        + '<div style="font-size:0.82rem;font-weight:600;color:var(--text-1);margin-top:4px">' + a.title + '</div>'
        + '<div style="font-size:0.75rem;color:var(--text-2);margin-top:2px">' + a.message + '</div>'
        + '<button type="button" onclick="resolveAlert(' + a.id + ',this)" style="margin-top:6px;padding:2px 10px;border-radius:10px;border:1px solid rgba(255,255,255,0.1);background:rgba(255,255,255,0.04);color:var(--text-2);font-size:0.68rem;cursor:pointer">✓ Resolve</button>';
    panel.insertBefore(card, panel.firstChild);
}

/* ── Resolve alert ── */
async function resolveAlert(id, btn) {
    try {
        if (window.insforge) await window.insforge.run('UPDATE farm_alerts SET is_resolved=TRUE, resolved_at=NOW() WHERE id=$1', [id]);
    } catch (e) { console.error('Operation failed:', e); }
    var card = btn ? btn.closest('.alert-card-item') : null;
    if (card) { card.style.opacity = '0.4'; card.style.textDecoration = 'line-through'; }
    window._alertCount = Math.max(0, window._alertCount - 1);
    _updateAlertBadge();
}

/* ── Toggle alert panel ── */
function toggleAlertPanel() {
    var panel = document.getElementById('alert-slide-panel');
    if (!panel) return;
    var open = panel.style.right === '0px';
    panel.style.right = open ? '-380px' : '0px';
    if (!open) { window._alertCount = 0; _updateAlertBadge(); _loadAlertHistory(); }
}

/* ── Load alert history from DB ── */
async function _loadAlertHistory() {
    if (!window.insforge) return;
    try {
        var hist = await window.insforge.query(
            "SELECT id, module, severity, title, message, is_resolved, alert_time FROM farm_alerts ORDER BY alert_time DESC LIMIT 50"
        );
        if (!hist || !hist.length) return;
        var panel = document.getElementById('alert-slide-panel');
        if (!panel) return;
        // Only add ones not already in panel
        var existingIds = new Set(Array.from(panel.querySelectorAll('.alert-card-item')).map(function (c) { return parseInt(c.getAttribute('data-alert-id') || 0); }));
        hist.forEach(function (a) {
            if (existingIds.has(a.id) || a.is_resolved) return;
            var cfg = _SEVERITY[a.severity] || _SEVERITY.INFO;
            var d = new Date(a.alert_time);
            var alertObj = { id: a.id, module: a.module, severity: a.severity, title: a.title, message: a.message || '', time: d.toLocaleDateString('en-IN') + ' ' + d.toLocaleTimeString('en-IN') };
            _injectAlertCard(alertObj, cfg);
        });
    } catch (e) { console.error('Operation failed:', e); }
}

/* ══════════════════════════════════════════════════════════════
   ALERT RULE EVALUATORS — One per module
   ══════════════════════════════════════════════════════════════ */

/* ── DAIRY: Milk yield drop ── */
async function _checkDairyAlerts() {
    if (!window.insforge) return;
    try {
        var today = new Date().toISOString().slice(0, 10);
        var d7ago = new Date(Date.now() - 7 * 86400000).toISOString().slice(0, 10);

        var res = await window.insforge.query(
            "SELECT collection_date, SUM(volume_l) as vol FROM dairy_milk_records WHERE collection_date >= '" + d7ago + "' GROUP BY collection_date ORDER BY collection_date DESC LIMIT 8"
        );
        if (!res || res.length < 2) return;

        var todayVol = parseFloat((res[0] || {}).vol) || 0;
        var avg7 = res.slice(1).reduce(function (s, r) { return s + (parseFloat(r.vol) || 0); }, 0) / Math.max(res.length - 1, 1);

        if (avg7 > 0 && todayVol < avg7 * 0.90) {
            var drop = ((1 - todayVol / avg7) * 100).toFixed(1);
            _fireAlert('Dairy', (drop > 20 ? 'CRITICAL' : 'WARNING'),
                'Milk Yield Drop: ' + drop + '% below average',
                'Today: ' + Math.round(todayVol) + ' L | 7-day avg: ' + Math.round(avg7) + ' L',
                todayVol, avg7 * 0.90);
        }

        // Fat% average check
        var fat = await window.insforge.query(
            "SELECT AVG(fat_pct) as fat FROM dairy_milk_records WHERE collection_date='" + today + "'"
        );
        if (fat && fat[0] && parseFloat(fat[0].fat) < 3.0) {
            _fireAlert('Dairy', 'WARNING', 'Low Milk Fat%: ' + parseFloat(fat[0].fat).toFixed(2) + '%',
                'Target >3.5% SNF quality standard. Check cow nutrition.', parseFloat(fat[0].fat), 3.0);
        }
    } catch (e) { console.warn('Dairy alert check error:', e); }
}

/* ── POULTRY: Mortality spike ── */
async function _checkPoultryAlerts() {
    if (!window.insforge) return;
    try {
        var today = new Date().toISOString().slice(0, 10);

        // Get total batch size (from latest body weight or a fixed baseline)
        var mort = await window.insforge.query(
            "SELECT SUM(count) as dead, shed_id FROM poultry_mortality WHERE mort_date='" + today + "' GROUP BY shed_id"
        );
        if (!mort || !mort.length) return;

        // Approximate flock size per shed — if we have it, otherwise use a threshold count
        mort.forEach(function (row) {
            var dead = parseInt(row.dead) || 0;
            if (dead > 50) {
                _fireAlert('Poultry', 'CRITICAL', 'High Mortality in Shed ' + row.shed_id + ': ' + dead + ' birds today',
                    'Investigate disease, heat stress, or ventilation failure. Notify Vet.', dead, 50);
            } else if (dead > 20) {
                _fireAlert('Poultry', 'WARNING', 'Elevated Mortality in Shed ' + row.shed_id + ': ' + dead + ' birds today',
                    'Above normal range. Monitor closely.', dead, 20);
            }
        });

        // HDP% drop
        var hdp = await window.insforge.query(
            "SELECT AVG(hdp_pct) as hdp FROM poultry_egg_collection WHERE collection_date='" + today + "'"
        );
        if (hdp && hdp[0] && parseFloat(hdp[0].hdp) < 70) {
            _fireAlert('Poultry', 'WARNING', 'Low HDP%: ' + parseFloat(hdp[0].hdp).toFixed(1) + '%',
                'Egg production below 70%. Check lighting, nutrition, age of flock.', parseFloat(hdp[0].hdp), 70);
        }
    } catch (e) { console.warn('Poultry alert check error:', e); }
}

/* ── AQUACULTURE: Water quality ── */
async function _checkAquaAlerts() {
    if (!window.insforge) return;
    try {
        var today = new Date().toISOString().slice(0, 10);
        var water = await window.insforge.query(
            "SELECT pond_id, do_level, ph_level, ammonia_ppm, temp_c FROM aqua_daily_water_records WHERE reading_date='" + today + "'"
        );
        if (!water || !water.length) return;

        water.forEach(function (p) {
            var do_ = parseFloat(p.do_level) || 0;
            var ph = parseFloat(p.ph_level) || 7;
            var nh3 = parseFloat(p.ammonia_ppm) || 0;
            var tmp = parseFloat(p.temp_c) || 28;

            if (do_ < 3.0) {
                _fireAlert('Aquaculture', 'CRITICAL', 'Critically Low DO in Pond ' + p.pond_id + ': ' + do_.toFixed(2) + ' mg/L',
                    'Below 3.0 mg/L — immediate aeration required to prevent mass mortality.', do_, 3.0);
            } else if (do_ < 4.0) {
                _fireAlert('Aquaculture', 'WARNING', 'Low DO in Pond ' + p.pond_id + ': ' + do_.toFixed(2) + ' mg/L',
                    'Below safe 4.0 mg/L threshold. Increase paddle wheel aeration.', do_, 4.0);
            }
            if (ph < 6.5 || ph > 8.5) {
                _fireAlert('Aquaculture', 'WARNING', 'pH Out of Range in Pond ' + p.pond_id + ': ' + ph.toFixed(1),
                    'Safe range: 6.5–8.5. Take corrective action (lime/CO2).', ph, 7.5);
            }
            if (nh3 > 0.5) {
                _fireAlert('Aquaculture', 'CRITICAL', 'High Ammonia in Pond ' + p.pond_id + ': ' + nh3.toFixed(2) + ' ppm',
                    'Toxic above 0.5 ppm. Reduce feed; increase water exchange immediately.', nh3, 0.5);
            }
            if (tmp > 32) {
                _fireAlert('Aquaculture', 'WARNING', 'High Water Temp in Pond ' + p.pond_id + ': ' + tmp.toFixed(1) + '°C',
                    'Above 32°C reduces dissolved oxygen and stresses fish.', tmp, 32);
            }
        });
    } catch (e) { console.warn('Aqua alert check error:', e); }
}

/* ── ENERGY: Grid & Solar ── */
async function _checkEnergyAlerts() {
    if (!window.insforge) return;
    try {
        var today = new Date().toISOString().slice(0, 10);

        // Solar — performance ratio drop
        var sol = await window.insforge.query(
            "SELECT array_id, performance_ratio FROM solar_readings WHERE reading_date='" + today + "' AND performance_ratio < 70"
        );
        if (sol && sol.length) {
            sol.forEach(function (s) {
                _fireAlert('Energy', 'WARNING', 'Low Solar PR on Array ' + s.array_id + ': ' + (parseFloat(s.performance_ratio) || 0).toFixed(1) + '%',
                    'Performance Ratio below 70%. Possible soiling, shading, or inverter issue.', parseFloat(s.performance_ratio), 70);
            });
        }

        // Grid — if no reading today at all (data gap)
        var grid = await window.insforge.query(
            "SELECT COUNT(*) as cnt FROM grid_daily_logs WHERE log_date='" + today + "'"
        );
        if (grid && grid[0] && parseInt(grid[0].cnt) === 0) {
            var hr = new Date().getHours();
            if (hr >= 20) { // Alert only in evening if no reading
                _fireAlert('Energy', 'INFO', 'No Grid Log Today',
                    'No Smart Grid daily reading entered. Field operator should update.', 0, 1);
            }
        }
    } catch (e) { console.warn('Energy alert check error:', e); }
}

/* ── FINANCE: Budget threshold ── */
async function _checkFinanceAlerts() {
    if (!window.insforge) return;
    try {
        var month = new Date().toISOString().slice(0, 7);
        var fin = await window.insforge.query(
            "SELECT type, SUM(amount) as total FROM finance_entries WHERE entry_date >= '" + month + "-01' GROUP BY type"
        );
        if (!fin || !fin.length) return;

        var rev = 0, exp = 0;
        fin.forEach(function (r) {
            if (r.type === 'Revenue') rev = parseFloat(r.total) || 0;
            else exp = parseFloat(r.total) || 0;
        });

        // If expenses > 85% of revenue → WARNING; > 100% → CRITICAL
        if (rev > 0) {
            var ratio = exp / rev;
            if (ratio > 1.0) {
                _fireAlert('Finance', 'CRITICAL', 'MTD Expenses Exceed Revenue',
                    'Expenses: ₹' + Math.round(exp / 100000) + ' L | Revenue: ₹' + Math.round(rev / 100000) + ' L | Ratio: ' + ratio.toFixed(2),
                    ratio, 1.0);
            } else if (ratio > 0.85) {
                _fireAlert('Finance', 'WARNING', 'High Expense Ratio: ' + (ratio * 100).toFixed(0) + '%',
                    'Expenses are ' + (ratio * 100).toFixed(0) + '% of revenue this month. Review cost centres.',
                    ratio, 0.85);
            }
        }

        // Outstanding CRM > ₹50L
        var out = await window.insforge.query(
            "SELECT SUM(invoice_value) as total FROM crm_deliveries WHERE payment_status='Pending'"
        );
        if (out && out[0] && parseFloat(out[0].total) > 5000000) {
            _fireAlert('Finance', 'WARNING', 'High Outstanding Receivables: ₹' + Math.round(parseFloat(out[0].total) / 100000) + ' L',
                'Pending CRM payments above ₹50L. Follow up with buyers.', parseFloat(out[0].total), 5000000);
        }
    } catch (e) { console.warn('Finance alert check error:', e); }
}

/* ── EQUIPMENT: Overdue service ── */
async function _checkEquipmentAlerts() {
    if (!window.insforge) return;
    try {
        var today = new Date().toISOString().slice(0, 10);
        var overdue = await window.insforge.query(
            "SELECT equipment_id, equipment_name, next_service_date FROM equipment_maintenance WHERE next_service_date < '" + today + "' AND is_completed = FALSE ORDER BY next_service_date ASC LIMIT 10"
        );
        if (!overdue || !overdue.length) return;
        overdue.forEach(function (e) {
            _fireAlert('Equipment', 'WARNING', 'Overdue Service: ' + (e.equipment_name || e.equipment_id),
                'Next service was due on ' + e.next_service_date + '. Schedule maintenance immediately.',
                0, 0);
        });
    } catch (e) { console.warn('Equipment alert check error:', e); }
}

/* ── VET: High admission load ── */
async function _checkVetAlerts() {
    if (!window.insforge) return;
    try {
        var today = new Date().toISOString().slice(0, 10);
        var adm = await window.insforge.query(
            "SELECT COUNT(*) as cnt, triage_level FROM vet_admissions WHERE admission_date='" + today + "' GROUP BY triage_level"
        );
        if (!adm || !adm.length) return;
        adm.forEach(function (r) {
            if ((r.triage_level === 'Critical' || r.triage_level === 'Emergency') && parseInt(r.cnt) >= 3) {
                _fireAlert('Vet', 'CRITICAL', parseInt(r.cnt) + ' CRITICAL/Emergency Admissions Today',
                    'High triage load on Vet Hospital. Ensure adequate staff coverage.', parseInt(r.cnt), 3);
            }
        });
    } catch (e) { console.warn('Vet alert check error:', e); }
}

/* ══════════════════════════════════════════════════════════════
   ALERT PANEL UI — Injected into DOM
   ══════════════════════════════════════════════════════════════ */
function _buildAlertPanel() {
    // Only create once
    if (document.getElementById('alert-slide-panel')) return;

    // Slide panel container
    var panel = document.createElement('div');
    panel.id = 'alert-slide-panel';
    panel.innerHTML = '<div style="display:flex;justify-content:space-between;align-items:center;padding:14px 16px;border-bottom:1px solid rgba(255,255,255,0.08);position:sticky;top:0;background:var(--panel-bg,#0f172a);z-index:1">'
        + '<span style="font-size:0.9rem;font-weight:700;color:var(--text-1,#e2e8f0)">🔔 Farm Alerts</span>'
        + '<button type="button" onclick="toggleAlertPanel()" style="background:none;border:none;color:var(--text-2,#94a3b8);font-size:1.2rem;cursor:pointer;padding:0">✕</button>'
        + '</div>'
        + '<div style="padding:8px 10px;font-size:0.72rem;color:var(--text-3,#64748b);border-bottom:1px solid rgba(255,255,255,0.05)">'
        + '<span id="alert-panel-count">Loading history...</span>'
        + '</div>'
        + '<div id="alert-panel-body" style="padding:8px;overflow-y:auto;max-height:calc(100vh - 130px)"></div>';
    document.body.appendChild(panel);

    // Re-target the body of the panel
    panel.querySelector('#alert-panel-body').id = 'alert-slide-panel';
    panel.querySelector('#alert-panel-body') || (panel.id = 'alert-slide-panel');
}

/* ── Wire bell icon in top-bar header to toggle panel ── */
function _wireAlertBell() {
    // Try to find the existing bell/alert button and wrap it
    var bellArea = document.querySelector('.alert-btn') || document.querySelector('[title="Alerts"]');
    if (!bellArea) return;

    // Add badge
    if (!document.getElementById('alert-count-badge')) {
        var badge = document.createElement('div');
        badge.id = 'alert-count-badge';
        badge.style.cssText = 'position:absolute;top:-6px;right:-8px;background:#ef4444;color:#fff;font-size:0.6rem;padding:2px 5px;border-radius:10px;font-weight:700;display:none;min-width:16px;text-align:center;';
        bellArea.style.position = 'relative';
        bellArea.appendChild(badge);
    }

    bellArea.onclick = function (e) {
        e.stopPropagation();
        toggleAlertPanel();
    };
    bellArea.style.cursor = 'pointer';
    bellArea.title = 'Farm Alerts';
}

/* ══════════════════════════════════════════════════════════════
   MASTER ALERT RUNNER — Runs all checks on schedule
   ══════════════════════════════════════════════════════════════ */
async function runAllAlertChecks() {
    try {
        await Promise.all([
            _checkDairyAlerts(),
            _checkPoultryAlerts(),
            _checkAquaAlerts(),
            _checkEnergyAlerts(),
            _checkFinanceAlerts(),
            _checkEquipmentAlerts(),
            _checkVetAlerts()
        ]);
    } catch (e) { console.warn('Alert engine error:', e); }
}

/* ── Boot on page load ── */
window.addEventListener('load', function () {
    setTimeout(function () {
        _buildAlertPanel();
        _wireAlertBell();
        // Request notification permission
        if (Notification && Notification.permission === 'default') Notification.requestPermission();
        // First run after 3 seconds (let analytics load first)
        setTimeout(runAllAlertChecks, 3000);
        // Then every 5 minutes
        setInterval(runAllAlertChecks, 300000);
        // Load history from DB
        setTimeout(_loadAlertHistory, 5000);
    }, 1500);
});





