/* ══════════════════════════════════════════════════════════
   7. CARBON CREDIT AUTO-CALCULATION
   Every energy reading auto-calculates tCO2 offset and
   posts to carbon_daily_credits if not already there.
   ══════════════════════════════════════════════════════════ */

async function _calculateCarbonOffset(source, kWh, readingDate) {
    if (!window.insforge || !kWh) return;
    try {
        var tCO2 = parseFloat(_CALC.co2FromKwh(kWh));
        var marketPricePerT = 850; // ₹850/tCO2 approx VCS rate
        var revenue = Math.round(tCO2 * marketPricePerT);

        await window.insforge.insert('carbon_daily_credits', {
            credit_date: readingDate,
            source: source,
            kwh_or_units: kWh,
            tco2_offset: tCO2,
            revenue_estimate: revenue,
            registry: 'VCS'
        });

        // Auto-post to finance as INFO (not actual revenue until verified)
        if (revenue > 0) {
            await window.insforge.insert('finance_entries', {
                type: 'Revenue',
                category: 'Carbon Credits',
                amount: revenue,
                notes: 'Auto: ' + source + ' carbon offset ' + tCO2.toFixed(3) + ' tCO2',
                entry_date: readingDate,
                status: 'Estimated'
            });
        }
        console.log('[Carbon] Auto-offset:', source, kWh, 'kWh =', tCO2, 'tCO2 = ₹' + revenue);
    } catch (e) { console.warn('Carbon offset error:', e); }
}

