/* ============================================================
   PHASE 8 — MULTI-USER ROLES & SESSION MANAGEMENT
   PHASE-8-RBAC */

/* ══════════════════════════════════════════════════════════
   SESSION MANAGER
   ══════════════════════════════════════════════════════════ */
var _SESSION = {
    _data: null,

    load: function () {
        try {
            var raw = localStorage.getItem('vd_session');
            if (!raw) return null;
            var s = JSON.parse(raw);
            if (s.expiresAt < Date.now()) {
                localStorage.removeItem('vd_session');
                return null;
            }
            _SESSION._data = s;
            return s;
        } catch (e) { return null; }
    },

    get role() { return (_SESSION._data || {}).role || 'admin'; },
    get name() { return (_SESSION._data || {}).name || 'User'; },
    get email() { return (_SESSION._data || {}).email || ''; },
    get initial() { return _SESSION.name.charAt(0).toUpperCase(); },

    logout: function () {
        localStorage.removeItem('vd_session');
        window.location.href = 'login.html';
    },

    extend: function () {
        if (_SESSION._data) {
            _SESSION._data.expiresAt = Date.now() + 8 * 60 * 60 * 1000;
            localStorage.setItem('vd_session', JSON.stringify(_SESSION._data));
        }
    }
};

/* ══════════════════════════════════════════════════════════
   ROLE ACCESS MAP
   Defines which sidebar pages each role can access.
   ══════════════════════════════════════════════════════════ */
var _ROLE_ACCESS = {
    admin: ['*'], // full access

    field_worker: [
        'overview', 'cattle', 'poultry', 'aqua', 'vet',
        'tree', 'vermi', 'solar', 'wind', 'biogas',
        'hydro', 'kinetic', 'hydrogen'
    ],

    vet: [
        'overview', 'vet', 'cattle', 'poultry', 'aqua'
    ],

    finance: [
        'overview', 'finance', 'crm', 'cattle', 'poultry',
        'aqua', 'solar', 'wind', 'biogas', 'hydrogen', 'tree', 'vermi'
    ],

    zone_manager: [
        'overview', 'cattle', 'poultry', 'aqua', 'vet',
        'tree', 'vermi', 'finance', 'crm', 'solar', 'wind'
    ],

    energy_ops: [
        'overview', 'solar', 'wind', 'biogas', 'hydrogen',
        'hydro', 'kinetic', 'grid'
    ]
};

function _canAccess(page) {
    var allowed = _ROLE_ACCESS[_SESSION.role] || [];
    if (allowed[0] === '*') return true;
    return allowed.indexOf(page) !== -1;
}

/* ══════════════════════════════════════════════════════════
   NAV RESTRICTOR — hides/dims nav items user can't access
   ══════════════════════════════════════════════════════════ */
function _applyRoleNavRestrictions() {
    var role = _SESSION.role;
    if (role === 'admin') return; // admin sees all

    var navItems = document.querySelectorAll('.menu-item[data-page]');
    navItems.forEach(function (item) {
        var page = item.getAttribute('data-page');
        if (!_canAccess(page)) {
            item.style.opacity = '0.25';
            item.style.pointerEvents = 'none';
            item.title = 'Access restricted for your role';
            item.setAttribute('data-restricted', 'true');
        }
    });

    // Show role badge on nav items the user owns
    var allowed = _ROLE_ACCESS[role] || [];
    if (allowed[0] !== '*' && allowed.length <= 6) {
        allowed.forEach(function (page) {
            var item = document.querySelector('.menu-item[data-page="' + page + '"]');
            if (item) item.style.borderLeft = '2px solid rgba(0,176,255,0.4)';
        });
    }
}

/* ══════════════════════════════════════════════════════════
   PAGE GUARD — intercepts nav clicks for restricted pages
   ══════════════════════════════════════════════════════════ */
function _guardNavClicks() {
    document.addEventListener('click', function (e) {
        var ni = e.target.closest('.menu-item[data-page]');
        if (!ni) return;
        if (ni.getAttribute('data-restricted') === 'true') {
            e.preventDefault(); e.stopPropagation();
            _showAccessDenied(ni.getAttribute('data-page'));
        }
    }, true); // capture phase
}

function _showAccessDenied(page) {
    var toast = document.createElement('div');
    toast.style.cssText = 'position:fixed;top:70px;right:20px;background:rgba(239,68,68,0.15);border:1px solid rgba(239,68,68,0.3);color:#fca5a5;padding:12px 18px;border-radius:12px;font-size:0.8rem;font-weight:600;z-index:10000;max-width:280px;';
    toast.innerHTML = '🔒 Access Restricted<br><span style="font-weight:400;font-size:0.72rem">Module "' + page + '" is not available for your role (' + _SESSION.role.replace('_', ' ') + ').</span>';
    document.body.appendChild(toast);
    setTimeout(function () { toast.style.opacity = '0'; toast.style.transition = 'opacity 0.5s'; setTimeout(function () { toast.remove(); }, 500); }, 3000);
}

/* ══════════════════════════════════════════════════════════
   HEADER USER PROFILE WIDGET
   ══════════════════════════════════════════════════════════ */
