// ── SMART GRID AI LOGIC ──
let _sgInitialized = false;
let _sgInterval = null;

function initSmartGrid() {
    if (_sgInitialized) return;
    const ctxFlow = document.getElementById('sgFlowChart');
    if (!ctxFlow) return;
    _sgInitialized = true;

    // Simulate Values
    function _animateVal(id, b, v, isD) {
        let el = document.getElementById(id);
        if (!el) return;
        el.classList.remove('flash-update');
        void el.offsetWidth;
        let p = 1 + (Math.random() * v * 2 - v);
        el.innerText = isD ? (b * p).toFixed(1) : Math.round(b * p).toLocaleString();
        el.classList.add('flash-update');
    }

    if (_sgInterval) clearInterval(_sgInterval);
    _sgInterval = setInterval(() => {
        if (!document.getElementById('sg-container-root')) return;
        _animateVal('sg-val-gen', 4512, 0.02, false);
        _animateVal('sg-val-dem', 3847, 0.015, false);
        _animateVal('sg-val-exp', 312, 0.05, false);
        _animateVal('sg-val-eff', 94.2, 0.005, true);
        _animateVal('sg-val-rev', 4.2, 0.01, true);

        const ud = (id, cap, bp, wT) => {
            let el = document.getElementById('sg-lb-' + id);
            let tx = document.getElementById('sg-lb-' + id + '-txt');
            if (!el || !tx) return;
            let np = bp + (Math.random() * 4 - 2);
            if (np > 100) np = 100;
            let u = cap * (np / 100);
            el.style.width = np + '%';
            tx.innerText = (wT ? Math.round(u).toLocaleString() : u.toFixed(1)) + ' / ' + cap.toLocaleString() + ' MW (' + np.toFixed(0) + '%)';
            if (wT) el.className = 'sg-load-bar-fill ' + (np >= 85 ? 'sg-bg-yellow' : 'sg-bg-green');
        };
        ud('hyd', 5, 72, false);
        ud('kur', 3024, 87, true);
        ud('gad', 512, 58, false);
        ud('bel', 971, 64, false);
    }, 5000);

    // Flow Chart
    if (typeof Chart !== 'undefined') {
        Chart.defaults.color = '#94a3b8';
        Chart.defaults.font.family = "'Exo 2', sans-serif";
        Chart.defaults.scale.grid.color = 'rgba(26, 58, 92, 0.5)';

        let fL = Array.from({ length: 24 }, (_, i) => i.toString().padStart(2, '0') + ':00');
        let gD = fL.map((_, i) => 2000 + Math.sin(i / 3) * 2500 + Math.random() * 200);
        let dD = fL.map((_, i) => 2500 + Math.sin(i / 4) * 1000 + Math.random() * 300);
        let eD = gD.map((g, i) => Math.max(0, g - dD[i]));
        new Chart(ctxFlow.getContext('2d'), {
            type: 'line',
            data: {
                labels: fL,
                datasets: [
                    { label: 'Generation (MW)', data: gD, borderColor: '#00ffe0', backgroundColor: 'rgba(0, 255, 224, 0.1)', fill: true, pointRadius: 0, tension: 0.4 },
                    { label: 'Demand (MW)', data: dD, borderColor: '#f59e0b', pointRadius: 0, tension: 0.4 },
                    { label: 'Export (MW)', data: eD, borderColor: '#10b981', borderDash: [5, 5], pointRadius: 0, tension: 0.4 }
                ]
            },
            options: { responsive: true, maintainAspectRatio: false, interaction: { mode: 'index', intersect: false }, animation: false }
        });

        // Mix Chart
        new Chart(document.getElementById('sgMixChart').getContext('2d'), {
            type: 'doughnut',
            data: {
                labels: ['Solar', 'Wind', 'Biogas', 'Hydro', 'H₂', 'Kinetic'],
                datasets: [{ data: [69, 14, 4, 1, 11, 1], backgroundColor: ['#ffb300', '#4fc3f7', '#66bb6a', '#29b6f6', '#b39ddb', '#ff8a65'], borderWidth: 0 }]
            },
            options: { responsive: true, maintainAspectRatio: false, cutout: '75%', plugins: { legend: { position: 'right', labels: { color: '#e8f4fd', usePointStyle: true } } } }
        });

        // Forecast Chart
        let nH = new Date().getHours();
        let fcL = ['Now', (nH + 1) % 24 + ':00', (nH + 2) % 24 + ':00', (nH + 3) % 24 + ':00', (nH + 4) % 24 + ':00', (nH + 5) % 24 + ':00', (nH + 6) % 24 + ':00'];
        new Chart(document.getElementById('sgForecastChart').getContext('2d'), {
            type: 'line',
            data: {
                labels: fcL,
                datasets: [
                    { label: 'Predicted Gen', data: [4512, 4320, 4100, 3800, 3200, 2500, 1800], borderColor: '#b39ddb', borderDash: [5, 5], tension: 0.4 },
                    { label: 'Predicted Dem', data: [3847, 3900, 4050, 4200, 4300, 4100, 3800], borderColor: '#f59e0b', tension: 0.4 }
                ]
            },
            options: { responsive: true, maintainAspectRatio: false }
        });
    }
}

document.addEventListener('DOMSubtreeModified', () => {
    if (document.getElementById('sg-container-root') && !_sgInitialized) {
        initSmartGrid();
    } else if (!document.getElementById('sg-container-root')) {
        _sgInitialized = false;
    }
});

