function biogasTab(tab) {
    document.querySelectorAll('#biogas .tab-btn').forEach(b => b.classList.remove('active'));
    document.querySelectorAll('#biogas .tab-panel').forEach(p => p.classList.remove('active'));
    const btn = document.querySelector(`#biogas .tab-btn[data-tab="${tab}"]`);
    const panel = document.getElementById(`biogas-${tab}`);
    if (btn) btn.classList.add('active');
    if (panel) panel.classList.add('active');
}

