function filterTasks(status) {
    const container = document.getElementById('page-container');
    if (!container) return;
    const rows = container.querySelectorAll('.task-row, tr[data-status]');
    rows.forEach(r => {
        if (!status || status === 'all') { r.style.display = ''; return; }
        const st = r.getAttribute('data-status') || r.textContent;
        r.style.display = st.toLowerCase().includes(status.toLowerCase()) ? '' : 'none';
    });
}
window.filterTasks = filterTasks;

function filterComms(type) {
    const container = document.getElementById('page-container');
    if (!container) return;
    const rows = container.querySelectorAll('.comm-row, tr[data-type]');
    rows.forEach(r => {
        if (!type || type === 'all') { r.style.display = ''; return; }
        const t = r.getAttribute('data-type') || r.textContent;
        r.style.display = t.toLowerCase().includes(type.toLowerCase()) ? '' : 'none';
    });
}
window.filterComms = filterComms;

/* ============================================================
   PHASE 4 FIX — Loading Timeout (10s) for all "Loading..." texts
   ============================================================ */
(function () {
    setTimeout(function () {
        document.querySelectorAll('p, div, span, td').forEach(function (el) {
            if (el.textContent.match(/^Loading .{2,50}\.\.\./)) {
                if (el.textContent.trim().startsWith('Loading')) {
                    el.innerHTML = '<span style="color:rgba(200,214,229,0.4);font-style:italic">Data unavailable — check connection</span>';
                }
            }
        });
    }, 10000);
})();

/* END PHASE 1 + 4 FIX */


/* ============================================================
   RUNTIME UI/UX FIXES — Auto-applied on DOMContentLoaded
   Fixes: button types, empty table states, loading timeouts
   ============================================================ */
document.addEventListener('DOMContentLoaded', function () {

    /* Fix 1: Add type='button' to all buttons missing it */
    document.querySelectorAll('button:not([type])').forEach(function (btn) {
        btn.setAttribute('type', 'button');
    });

    /* Fix 2: Add empty-state message to empty tbodies after 5s */
    setTimeout(function () {
        document.querySelectorAll('tbody').forEach(function (tb) {
            if (tb.children.length === 0 && !tb.dataset.emptyHandled) {
                tb.dataset.emptyHandled = '1';
                var tr = document.createElement('tr');
                var td = document.createElement('td');
                td.setAttribute('colspan', '20');
                td.style.cssText = 'text-align:center;padding:24px;color:rgba(200,214,229,0.35);font-style:italic;';
                td.textContent = 'No data available';
                tr.appendChild(td);
                tb.appendChild(tr);
            }
        });
    }, 5000);

    /* Fix 3: Replace stuck 'Loading...' text after 12s */
    setTimeout(function () {
        document.querySelectorAll('p, div, span, td, h3, h4').forEach(function (el) {
            var t = el.textContent.trim();
            if (t.startsWith('Loading ') && t.endsWith('...') && t.length < 60) {
                el.style.color = 'rgba(200,214,229,0.35)';
                el.style.fontStyle = 'italic';
                el.textContent = t.replace('Loading ', '').replace('...', '') + ' — data unavailable';
            }
        });
    }, 12000);

    /* Fix 4: Observe future page renders for new buttons without type */
    var observer = new MutationObserver(function (mutations) {
        mutations.forEach(function (m) {
            m.addedNodes.forEach(function (node) {
                if (node.nodeType === 1) {
                    if (node.tagName === 'BUTTON' && !node.type) node.type = 'button';
                    var btns = node.querySelectorAll ? node.querySelectorAll('button:not([type])') : [];
                    btns.forEach(function (b) { b.type = 'button'; });
                }
            });
        });
    });
    var pc = document.getElementById('page-container');
    if (pc) observer.observe(pc, { childList: true, subtree: true });
});

/* END RUNTIME FIXES */


