/* ---- A. TOAST NOTIFICATION SYSTEM ---- */
(function () {
    // Create toast container
    var tc = document.createElement('div');
    tc.id = 'toast-container';
    tc.style.cssText = 'position:fixed;top:16px;right:16px;z-index:9999;display:flex;flex-direction:column;gap:8px;pointer-events:none;max-width:380px;';
    document.body.appendChild(tc);

    window.showToast = function (message, type, duration) {
        type = type || 'info';
        duration = duration || 3500;

        var icons = {
            success: '<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"/><polyline points="22 4 12 14.01 9 11.01"/></svg>',
            error: '<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="10"/><line x1="15" y1="9" x2="9" y2="15"/><line x1="9" y1="9" x2="15" y2="15"/></svg>',
            warning: '<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>',
            info: '<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="10"/><line x1="12" y1="16" x2="12" y2="12"/><line x1="12" y1="8" x2="12.01" y2="8"/></svg>'
        };

        var colors = {
            success: { bg: 'rgba(0,230,118,0.12)', border: 'rgba(0,230,118,0.3)', color: '#00e676' },
            error: { bg: 'rgba(255,82,82,0.12)', border: 'rgba(255,82,82,0.3)', color: '#ff5252' },
            warning: { bg: 'rgba(255,171,0,0.12)', border: 'rgba(255,171,0,0.3)', color: '#ffab00' },
            info: { bg: 'rgba(0,176,255,0.12)', border: 'rgba(0,176,255,0.3)', color: '#00b0ff' }
        };

        var c = colors[type] || colors.info;
        var toast = document.createElement('div');
        toast.style.cssText = 'display:flex;align-items:center;gap:10px;padding:12px 18px;border-radius:10px;font-size:0.85rem;font-family:Inter,sans-serif;pointer-events:auto;cursor:pointer;backdrop-filter:blur(16px);border:1px solid ' + c.border + ';background:' + c.bg + ';color:' + c.color + ';box-shadow:0 8px 32px rgba(0,0,0,0.3);animation:toastIn 0.3s ease;min-width:220px;';
        toast.innerHTML = (icons[type] || icons.info) + '<span style="flex:1;color:#e0eaf4;font-weight:500">' + message + '</span>';
        toast.onclick = function () { toast.remove(); };

        var container = document.getElementById('toast-container');
        container.appendChild(toast);

        setTimeout(function () {
            toast.style.animation = 'toastOut 0.25s ease forwards';
            setTimeout(function () { toast.remove(); }, 250);
        }, duration);
    };
})();

