(function () {
    var style = document.createElement('style');
    style.textContent = '@keyframes shimmer{0%{background-position:-200% 0}100%{background-position:200% 0}}.skeleton-line{height:14px;border-radius:6px;background:linear-gradient(90deg,rgba(255,255,255,0.03) 0%,rgba(255,255,255,0.08) 40%,rgba(255,255,255,0.03) 80%);background-size:200% 100%;animation:shimmer 1.5s ease infinite;margin:8px 0}.skeleton-block{height:80px;border-radius:10px;background:linear-gradient(90deg,rgba(255,255,255,0.02) 0%,rgba(255,255,255,0.06) 40%,rgba(255,255,255,0.02) 80%);background-size:200% 100%;animation:shimmer 1.5s ease infinite;margin:12px 0}';
    document.head.appendChild(style);

    // Replace Loading text with skeleton after 1s
    setTimeout(function () {
        document.querySelectorAll('p, div, span, td, h3').forEach(function (el) {
            var t = el.textContent.trim();
            if (t.startsWith('Loading ') && t.endsWith('...') && t.length < 60 && el.children.length === 0) {
                el.innerHTML = '<div class="skeleton-line" style="width:70%"></div><div class="skeleton-line" style="width:50%"></div><div class="skeleton-line" style="width:85%"></div>';
                el.style.padding = '8px';
            }
        });
    }, 1500);
})();

/* ---- D. safeFetch WRAPPER ---- */
window.safeFetch = async function (url, options, fallbackMsg) {
    try {
        var res = await fetch(url, options || {});
        if (!res.ok) throw new Error('HTTP ' + res.status);
        return await res.json();
    } catch (e) {
        console.error('safeFetch error:', url, e);
        if (window.showToast) {
            window.showToast(fallbackMsg || 'Connection error — check network', 'error', 5000);
        }
        return null;
    }
};

